-- Schema for Domain: equipment | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:37

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`equipment` COMMENT 'SSOT for all agricultural equipment and fleet assets including tractors, combines, planters, sprayers, and irrigation systems. Tracks asset registration, telematics data (John Deere Operations Center), OEE metrics, preventive and corrective maintenance schedules (PM/CMMS), CAPEX/OPEX cost allocation, parts inventory, and precision agriculture hardware integration (GPS/RTK receivers, VRA controllers). Supports operational efficiency and asset lifecycle management aligned with ISO 55000.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset` (
    `asset_id` BIGINT COMMENT 'Unique system-generated surrogate key identifying each agricultural equipment or fleet asset record in the master registry. Primary key for the asset data product.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Agricultural assets (tractors, harvesters, implements) are acquired via CAPEX purchase orders. Linking asset to its acquisition PO enables fixed asset lifecycle traceability from procurement through d',
    `asset_category_id` BIGINT COMMENT 'Foreign key reference to the asset class/category reference product defining the equipment classification hierarchy (e.g., tractor, combine harvester, planter, sprayer, irrigation system, precision agriculture hardware).',
    `capital_project_id` BIGINT COMMENT 'Foreign key linking to finance.capital_project. Business justification: Equipment acquisitions in agriculture are funded through approved CAPEX projects (e.g., combine fleet renewal, precision ag hardware rollout). Linking asset to its funding capital_project enables CAPE',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Assets such as grain augers, conveyors, and forklifts are permanently stationed at supply facilities (grain elevators, packing houses). Asset management and maintenance routing requires knowing the ho',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or agricultural operation to which this asset is primarily assigned for operational and cost allocation purposes.',
    `fixed_asset_id` BIGINT COMMENT 'Foreign key linking to finance.fixed_asset. Business justification: Farm equipment (tractors, combines, irrigation systems) are capitalized on the fixed asset register. This link enables asset register reconciliation, depreciation tracking (MACRS/Section 179), and GAA',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: CCP-designated equipment (wash stations, pasteurizers, cold storage, chemical applicators) must be linked to their governing HACCP plan under FSMA Preventive Controls. This link enables auditors to id',
    `parcel_id` BIGINT COMMENT 'Foreign key linking to land.parcel. Business justification: Fixed assets (irrigation pivots, grain bins, buildings) are legally attached to a specific land parcel for property tax assessment, title records, and insurance purposes. Fixed asset registers in agri',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Certain agricultural assets (aerial applicators, irrigation pumps drawing from permitted water sources, CAFO equipment) operate under specific permits. Linking asset to permit enables permit expiry al',
    `territory_id` BIGINT COMMENT 'Foreign key linking to sales.territory. Business justification: Equipment assets are deployed within defined sales territories in large-scale ag operations. Territory-based equipment capacity planning and custom hire sales reporting require knowing which assets ar',
    `acquisition_cost` DECIMAL(18,2) COMMENT 'Original purchase price or total capitalized cost of the asset at acquisition, representing the Capital Expenditure (CAPEX) investment. Includes purchase price, freight, installation, and commissioning costs. Denominated in USD. Sourced from SAP S/4HANA FI/AM.',
    `acquisition_date` DATE COMMENT 'Date on which the asset was acquired (purchased, leased, or transferred into the fleet). Marks the start of the asset lifecycle for depreciation, warranty, and compliance tracking. Sourced from SAP S/4HANA FI/AM module.',
    `asset_name` STRING COMMENT 'Human-readable descriptive name or designation for the asset (e.g., John Deere 8R 410 Tractor - North Field Unit 3). Used for operational identification and reporting.',
    `commissioning_date` DATE COMMENT 'Date on which the asset was formally placed into service and became operational. May differ from acquisition date if installation, calibration, or certification was required prior to first use. Triggers start of depreciation in SAP S/4HANA.',
    `cost_center_code` STRING COMMENT 'SAP S/4HANA Controlling (CO) module cost center code to which the assets Operational Expenditure (OPEX) and depreciation charges are allocated. Enables farm-level and department-level cost reporting and EBITDA analysis.',
    `current_book_value` DECIMAL(18,2) COMMENT 'Current net book value of the asset after accumulated depreciation, calculated as acquisition cost minus total accumulated depreciation to date. Used for financial reporting, insurance valuation, and disposal decisions. Denominated in USD.',
    `decommission_date` DATE COMMENT 'Date on which the asset was formally retired from service and decommissioned. Marks the end of the operational lifecycle for depreciation cessation, disposal processing, and regulatory reporting. Null if asset is still active.',
    `depreciation_method` STRING COMMENT 'Accounting method used to calculate periodic depreciation of the asset. Straight-line spreads cost evenly; declining balance accelerates early depreciation; units of production ties depreciation to actual usage hours. Configured in SAP S/4HANA FI/AM.. Valid values are `straight_line|declining_balance|sum_of_years_digits|units_of_production`',
    `engine_hours` DECIMAL(18,2) COMMENT 'Cumulative total engine or operating hours recorded on the asset since manufacture or last major overhaul. Primary usage metric for maintenance scheduling (e.g., 250-hour, 500-hour service intervals), depreciation under units-of-production method, and Overall Equipment Effectiveness (OEE) calculation. Sourced from John Deere Operations Center telematics.',
    `engine_power_kw` DECIMAL(18,2) COMMENT 'Rated engine power output of the asset in kilowatts (kW) as specified by the manufacturer. Used for equipment capability matching to field operations, fuel consumption benchmarking, and EPA emissions classification.',
    `fuel_type` STRING COMMENT 'Type of fuel or energy source used by the asset. Relevant for fuel cost allocation, emissions reporting (EPA Tier 4 Final compliance), and sustainability tracking under ISCC and ISO 14001 environmental management standards.. Valid values are `diesel|gasoline|lpg|electric|hybrid|natural_gas`',
    `gps_rtk_enabled` BOOLEAN COMMENT 'Indicates whether the asset is equipped with a Global Positioning System (GPS) / Real-Time Kinematic (RTK) positioning receiver for precision agriculture operations including Variable Rate Application (VRA), auto-steer, and field mapping. True = RTK-capable; False = no precision positioning hardware.',
    `insurance_expiry_date` DATE COMMENT 'Date on which the current insurance policy for the asset expires. Triggers renewal workflow to ensure continuous coverage and compliance with financing covenants and regulatory requirements.',
    `insurance_policy_number` STRING COMMENT 'Reference number of the insurance policy covering this asset against loss, damage, or liability. Used for claims processing, risk management reporting, and compliance with lender insurance requirements for financed equipment.',
    `last_inspection_date` DATE COMMENT 'Date of the most recent formal safety or regulatory inspection performed on the asset. Used to track compliance with OSHA equipment safety standards, GLOBALG.A.P. equipment hygiene requirements, and internal audit schedules.',
    `lifecycle_stage` STRING COMMENT 'Current lifecycle stage of the asset per ISO 55000 asset management framework. Drives maintenance scheduling, capital planning, and disposal workflows. [ENUM-REF-CANDIDATE: acquisition|commissioning|operational|standby|maintenance|decommissioned|disposed — promote to reference product]',
    `make` STRING COMMENT 'Name of the original equipment manufacturer (OEM) of the asset (e.g., John Deere, Case IH, AGCO, Kubota, Trimble). Used for vendor management, parts sourcing, and warranty claims.',
    `model` STRING COMMENT 'Manufacturer model designation of the asset (e.g., 8R 410, X9 1100, R4045). Combined with make and year to uniquely identify the equipment specification for parts compatibility and performance benchmarking.',
    `model_year` STRING COMMENT 'Manufacturer model year of the asset (e.g., 2022). Used for depreciation scheduling, technology generation classification, and compliance with emissions standards (EPA Tier 4 Final).',
    `next_service_date` DATE COMMENT 'Date on which the next preventive maintenance (PM) service is scheduled for the asset based on the Computerized Maintenance Management System (CMMS) schedule. Derived from last service date plus service interval. Sourced from SAP S/4HANA PM module maintenance plans.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, special configuration details, known defects, or other relevant information about the asset that does not fit structured fields. Used by fleet managers and maintenance technicians for contextual documentation.',
    `odometer_km` DECIMAL(18,2) COMMENT 'Cumulative distance traveled by the asset in kilometers, applicable to self-propelled vehicles (tractors, combines, sprayers, transport vehicles). Used for road-transport maintenance scheduling and fleet management. Sourced from John Deere Operations Center or vehicle ECU. Null for stationary or non-motorized equipment.',
    `operational_status` STRING COMMENT 'Current operational readiness status of the asset indicating whether it is available for field deployment. Active = deployed and operational; Standby = available but not deployed; Under Repair = in maintenance; Out of Service = unavailable; Decommissioned = retired from service.. Valid values are `active|standby|under_repair|out_of_service|decommissioned`',
    `ownership_type` STRING COMMENT 'Classification of the assets ownership or financing arrangement. Owned = outright purchase (CAPEX); Leased = finance or operating lease (OPEX/IFRS 16); Rented = short-term hire; Contract Hire = long-term managed service. Drives financial treatment under GAAP/IFRS 16.. Valid values are `owned|leased|rented|contract_hire|shared`',
    `record_created_timestamp` TIMESTAMP COMMENT 'Timestamp when the asset master record was first created in the system. Supports audit trail requirements, data lineage tracking, and SOX financial reporting controls. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `record_updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the asset master record was most recently modified. Supports change tracking, audit trail requirements, and Silver Layer incremental load processing in the Databricks Lakehouse. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `registration_expiry_date` DATE COMMENT 'Date on which the current government or regulatory registration for the asset expires. Triggers renewal workflow to maintain legal compliance for road use and regulatory inspections.',
    `registration_number` STRING COMMENT 'Government or regulatory authority registration number for the asset where required (e.g., state DMV registration for road-going vehicles, USDA/APHIS equipment registration). Null for non-registered implements.',
    `salvage_value` DECIMAL(18,2) COMMENT 'Estimated residual or salvage value of the asset at the end of its useful life. Used as the basis for depreciation calculations under straight-line and declining balance methods. Denominated in USD.',
    `serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number for the equipment unit. Used for warranty tracking, recall management, and manufacturer service records. Key identifier in John Deere Operations Center.',
    `tag` STRING COMMENT 'Internally assigned physical asset tag or barcode label affixed to the equipment for inventory tracking and identification during audits and maintenance. Aligns with SAP S/4HANA PM asset tag field.. Valid values are `^[A-Z0-9-]{3,20}$`',
    `telematics_device_code` STRING COMMENT 'Unique identifier of the telematics device or machine connectivity unit installed on the asset and registered in the John Deere Operations Center platform. Enables real-time GPS tracking, remote diagnostics, fuel consumption monitoring, and field data synchronization.',
    `useful_life_years` STRING COMMENT 'Estimated useful economic life of the asset in years, used as the basis for straight-line depreciation calculations and capital replacement planning. Defined at acquisition per GAAP/IFRS guidelines.',
    `vin` STRING COMMENT '17-character Vehicle Identification Number assigned to motorized agricultural vehicles (tractors, combines, self-propelled sprayers) per ISO 3779 standard. Null for non-motorized implements.. Valid values are `^[A-HJ-NPR-Z0-9]{17}$`',
    `vra_controller_enabled` BOOLEAN COMMENT 'Indicates whether the asset is equipped with a Variable Rate Application (VRA) controller enabling prescription-based variable rate seeding, fertilization, or chemical application. Supports precision agriculture workflows in Trimble Ag Software and Climate FieldView.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the manufacturer or dealer warranty for the asset expires. Used to trigger preventive maintenance scheduling under warranty terms and to determine whether repair costs are chargeable to the vendor or internal Operational Expenditure (OPEX) budget.',
    CONSTRAINT pk_asset PRIMARY KEY(`asset_id`)
) COMMENT 'Master registry of all agricultural equipment and fleet assets including tractors, combines, planters, sprayers, irrigation systems, and precision agriculture hardware. Captures asset identification (serial number, VIN, asset tag), make, model, year, asset class/category reference, acquisition date, acquisition cost (CAPEX), current book value, depreciation method, operational status (active/standby/decommissioned), assigned farm/field, GPS/RTK integration flag, telematics device ID (John Deere Operations Center), ISO 55000 lifecycle stage, salvage value, and regulatory compliance certifications. SSOT for all equipment identity, registration, and financial summary data. Central master record referenced by all transactional products in the equipment domain.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset_category` (
    `asset_category_id` BIGINT COMMENT 'Unique surrogate identifier for each asset category record in the equipment classification hierarchy. Primary key for the asset_category reference table. [REFERENCE_LOOKUP role — canonical_skip_reason: This entity is a reference classification hierarchy / taxonomy table defining equipment types; per-role minimums for REFERENCE_LOOKUP are exempt, but MASTER_RESOURCE minimums are applied as best-fit given the entity carries rich descriptive, financial, and operational metadata beyond a simple code list.]',
    `parent_category_asset_category_id` BIGINT COMMENT 'Self-referencing identifier pointing to the parent category in the equipment classification hierarchy, enabling parent-child rollup reporting for CAPEX/OPEX budgeting and fleet planning. Null for top-level (root) categories.',
    `asset_tag_prefix` STRING COMMENT 'Standardized alphabetic prefix used when generating asset tag numbers for individual assets registered under this category (e.g., TRC for tractors, CMB for combines, SPR for sprayers). Ensures consistent asset identification across the enterprise fleet registry.. Valid values are `^[A-Z]{2,6}$`',
    `availability_target_pct` DECIMAL(18,2) COMMENT 'Target equipment availability rate (uptime as a percentage of scheduled operating time) for assets in this category, forming the availability component of the OEE calculation. Used in preventive maintenance scheduling and fleet planning to set maintenance frequency targets.',
    `capex_budget_account_code` STRING COMMENT 'General Ledger (GL) account code in SAP S/4HANA FI/CO to which capital expenditure for assets in this category is posted. Enables CAPEX budget tracking and variance reporting by equipment category. Aligned with GAAP/IFRS financial reporting chart of accounts.. Valid values are `^[A-Z0-9-]{4,20}$`',
    `category_code` STRING COMMENT 'Externally-known alphanumeric code uniquely identifying the equipment category within the enterprise taxonomy (e.g., TILL-001, PLANT-002, SPRAY-003). Used as the business key in SAP S/4HANA PM asset class configuration and cross-system integration with John Deere Operations Center fleet telematics.. Valid values are `^[A-Z0-9_]{2,20}$`',
    `category_description` STRING COMMENT 'Detailed narrative description of the equipment category, including its primary agricultural function, typical use cases, and operational context (e.g., tillage, planting, crop protection, harvesting, irrigation, livestock handling, precision ag hardware, transport fleet).',
    `category_name` STRING COMMENT 'Human-readable name of the equipment category (e.g., Row Crop Tractor, Combine Harvester, Center Pivot Irrigation System, Precision Ag RTK Receiver). Used in CAPEX/OPEX budgeting reports, fleet planning dashboards, and maintenance scheduling interfaces.',
    `category_status` STRING COMMENT 'Current lifecycle status of the asset category record. active indicates the category is in use for asset registration and fleet planning; deprecated indicates the category has been superseded and no new assets should be assigned; under_review indicates pending taxonomy governance approval.. Valid values are `active|inactive|deprecated|under_review`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this asset category record was first created in the system. Supports data lineage, audit trail, and taxonomy governance tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `depreciation_method` STRING COMMENT 'Standard depreciation calculation method applied to assets in this category for financial reporting purposes. Drives SAP S/4HANA FI-AA depreciation key assignment. Aligned with IFRS IAS 16 and GAAP ASC 360 requirements for agricultural equipment asset accounting.. Valid values are `straight_line|declining_balance|units_of_production|sum_of_years_digits`',
    `effective_from` DATE COMMENT 'Date from which this asset category definition becomes effective and valid for use in asset registration, budgeting, and fleet planning. Supports temporal validity management of the equipment taxonomy for historical reporting and audit trails.',
    `effective_until` DATE COMMENT 'Date after which this asset category definition is no longer valid for new asset registrations. Null indicates the category is open-ended with no planned expiry. Supports taxonomy versioning and deprecation management.',
    `equipment_class` STRING COMMENT 'Operational class of the equipment category aligned with core agricultural business processes (e.g., tillage, planting, spraying, harvesting, irrigation). Maps directly to John Deere Operations Center equipment class codes and SAP S/4HANA PM functional location structure. [ENUM-REF-CANDIDATE: tillage|planting|spraying|harvesting|irrigation|fertilization|precision_ag|livestock|transport|general_purpose — promote to reference product]',
    `equipment_domain` STRING COMMENT 'High-level domain classification grouping equipment categories into major operational areas of the agricultural enterprise. Drives top-level CAPEX/OPEX budget segmentation and OEE (Overall Equipment Effectiveness) benchmarking by domain. [ENUM-REF-CANDIDATE: field_equipment|precision_ag_hardware|irrigation_systems|livestock_handling|transport_fleet|storage_infrastructure|power_units|other — promote to reference product if domain list expands beyond 8 values]',
    `fuel_type` STRING COMMENT 'Primary fuel or energy source type for assets in this category. Used for fuel consumption budgeting, OPEX cost allocation, emissions reporting, and EPA compliance tracking. none applies to non-powered implements (e.g., tillage tools, trailers). [ENUM-REF-CANDIDATE: diesel|gasoline|electric|hybrid|lpg|natural_gas|none — 7 candidates stripped; promote to reference product]',
    `globalg_ap_equipment_type` STRING COMMENT 'Equipment type classification code as defined by GLOBALG.A.P. (Global Good Agricultural Practices) certification standards. Required for GLOBALG.A.P. audit documentation to demonstrate that equipment used in certified operations meets GAP (Good Agricultural Practices) requirements.',
    `gps_telematics_capable` BOOLEAN COMMENT 'Indicates whether assets in this category are equipped with or compatible with GPS/telematics hardware for real-time location tracking and operational data collection via John Deere Operations Center or equivalent fleet telematics platforms. True = telematics integration is standard for this category.',
    `hierarchy_level` STRING COMMENT 'Numeric depth of this category within the equipment taxonomy hierarchy (e.g., 1 = top-level domain such as Field Equipment, 2 = class such as Harvesting Equipment, 3 = type such as Combine Harvester). Supports rollup aggregation and drill-down analytics.',
    `hierarchy_path` STRING COMMENT 'Materialized path string representing the full ancestry of the category from root to current node (e.g., Field Equipment > Harvesting Equipment > Combine Harvester). Facilitates efficient tree traversal queries and breadcrumb navigation in fleet management UIs.',
    `inspection_frequency_months` STRING COMMENT 'Required frequency in calendar months between mandatory regulatory inspections for assets in this category (e.g., 12 months for annual EPA sprayer calibration, 6 months for OSHA-mandated safety checks). Null if inspection_required is False.',
    `inspection_governing_body` STRING COMMENT 'Name of the regulatory authority or standards body responsible for mandating inspections for assets in this category (e.g., EPA, OSHA, USDA APHIS, FDA, state department of agriculture). Supports compliance tracking and audit documentation.',
    `inspection_required` BOOLEAN COMMENT 'Indicates whether assets in this category are subject to mandatory regulatory inspection requirements (e.g., EPA pesticide application equipment calibration, OSHA safety inspections for operator-driven equipment, USDA/APHIS compliance checks for livestock handling equipment). True = regulatory inspection is required.',
    `jd_ops_center_category_code` STRING COMMENT 'Equipment category code as defined in John Deere Operations Center fleet telematics platform. Used for cross-system data reconciliation between the enterprise asset taxonomy and John Deere precision agriculture fleet management data feeds.',
    `oee_benchmark_target_pct` DECIMAL(18,2) COMMENT 'Industry benchmark target for Overall Equipment Effectiveness (OEE) expressed as a percentage (0–100) for assets in this category. Used as the KPI baseline for fleet performance monitoring in John Deere Operations Center and operational reporting dashboards. OEE = Availability × Performance × Quality.',
    `operator_license_required` BOOLEAN COMMENT 'Indicates whether operating assets in this category requires a specific operator license, certification, or training qualification (e.g., CDL for transport vehicles, pesticide applicator license for sprayers, OSHA-mandated forklift certification for material handling equipment). Supports workforce compliance management in SAP SuccessFactors.',
    `opex_budget_account_code` STRING COMMENT 'General Ledger (GL) account code in SAP S/4HANA FI/CO to which operational and maintenance expenditure for assets in this category is posted. Supports OPEX budget tracking, maintenance cost analysis, and EBITDA reporting by equipment category.. Valid values are `^[A-Z0-9-]{4,20}$`',
    `pesticide_applicator_cert_required` BOOLEAN COMMENT 'Indicates whether operating assets in this category requires a valid EPA-certified pesticide applicator license (e.g., self-propelled sprayers, aerial application equipment). Supports IPM (Integrated Pest Management) compliance and EPA regulatory audit readiness.',
    `pm_interval_days` STRING COMMENT 'Calendar-day interval between scheduled preventive maintenance events for assets in this category, used when calendar-based (rather than usage-based) PM scheduling is applicable (e.g., annual inspections, seasonal service). Complements pm_interval_hours for dual-trigger PM strategies.',
    `pm_interval_hours` STRING COMMENT 'Standard operating hours interval between scheduled preventive maintenance (PM) events for assets in this category (e.g., 250 hours for tractor engine service). Used to auto-generate PM work orders in SAP S/4HANA PM/CMMS and John Deere Operations Center maintenance scheduling.',
    `power_rating_hp` DECIMAL(18,2) COMMENT 'Typical or standard power rating in horsepower (HP) for assets in this category, representing the principal quantitative performance characteristic. Used for equipment matching (tractor-implement compatibility), fleet specification planning, and fuel consumption benchmarking.',
    `precision_ag_compatible` BOOLEAN COMMENT 'Indicates whether assets in this category support precision agriculture hardware integration, including RTK (Real-Time Kinematic) GPS receivers, VRA (Variable Rate Application) controllers, NDVI sensors, or FMIS (Farm Management Information System) data connectivity. Supports precision ag fleet planning.',
    `salvage_value_pct` DECIMAL(18,2) COMMENT 'Estimated residual (salvage) value at end of useful life expressed as a percentage of original acquisition cost, used in depreciation base calculation for assets in this category. Supports CAPEX planning and asset disposal valuation in SAP S/4HANA FI-AA.',
    `sap_asset_class_code` STRING COMMENT 'Corresponding asset class code in SAP S/4HANA FI-AA (Fixed Asset Accounting) module that maps to this equipment category. Enables direct integration between the equipment taxonomy and SAP financial asset accounting for depreciation, CAPEX tracking, and balance sheet reporting.. Valid values are `^[A-Z0-9]{4,10}$`',
    `sort_order` STRING COMMENT 'Numeric display sort order for presenting asset categories in user interfaces, reports, and dropdown lists within the equipment domain. Allows business-defined ordering independent of alphabetical or ID-based sequencing.',
    `standard_depreciation_life_years` DECIMAL(18,2) COMMENT 'Standard useful economic life in years assigned to all assets within this category for CAPEX depreciation scheduling and financial reporting. Used in SAP S/4HANA FI/CO asset accounting to default depreciation key and useful life at asset creation. Aligned with GAAP/IFRS IAS 16 useful life estimation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this asset category record was last modified. Supports change tracking, taxonomy governance audit trails, and Silver Layer incremental data processing in the Databricks Lakehouse.',
    `vra_controller_compatible` BOOLEAN COMMENT 'Indicates whether assets in this category are compatible with VRA (Variable Rate Application) controllers for precision input management (seed, fertilizer, pesticide). Supports VRA prescription execution tracking in Trimble Ag Software and Climate FieldView.',
    `weight_class` STRING COMMENT 'Standardized weight class of assets in this category, used for transport logistics planning, road permit requirements, soil compaction risk assessment, and field access restrictions. Aligns with USDA and DOT weight classification standards for agricultural equipment.. Valid values are `light|medium|heavy|extra_heavy`',
    CONSTRAINT pk_asset_category PRIMARY KEY(`asset_category_id`)
) COMMENT 'Reference classification hierarchy for agricultural equipment types and categories. Defines the taxonomy of equipment classes (e.g., tillage, planting, spraying, harvesting, irrigation, precision ag hardware, livestock handling, transport fleet) with category codes, parent-child hierarchy for rollup reporting, OEE benchmark targets per category, standard depreciation life, and applicable regulatory inspection requirements. Used for CAPEX/OPEX budgeting and fleet planning.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`telematics_reading` (
    `telematics_reading_id` BIGINT COMMENT 'Unique surrogate identifier for each telemetry event record streamed from IoT-enabled agricultural equipment. Primary key for the telematics_reading data product. Role: EVENT_LOG.',
    `asset_id` BIGINT COMMENT 'Reference to the equipment asset (tractor, combine, planter, sprayer, irrigation system) that emitted this telemetry event. EVENT_SOURCE_REFERENCE per EVENT_LOG role minimum.',
    `employee_id` BIGINT COMMENT 'Reference to the operator or machine driver logged into the equipment at the time of the telemetry reading. Supports hours-of-service compliance and operator performance analytics.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Telematics readings are streamed continuously from equipment during field operations. telematics_reading has asset_id, field_id, and vra_prescription_id but no FK to the specific field_operation conte',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or land parcel where the equipment was operating at the time of the reading. Supports field coverage monitoring and VRA audit trails.',
    `input_product_id` BIGINT COMMENT 'Foreign key linking to product.input_product. Business justification: Real-time telematics captures application_rate_actual during spraying operations. Direct FK to input_product enables automated label compliance monitoring — comparing actual application rate against m',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the active Variable Rate Application (VRA) prescription being executed by the equipment at the time of the reading. Supports precision agriculture audit trails and agrochemical application compliance.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Precision agriculture analytics correlate real-time telematics readings (fuel consumption, engine load, ground speed) with concurrent weather observations to model weather impacts on equipment perform',
    `application_rate_actual` DECIMAL(18,2) COMMENT 'Actual rate of material (seed, fertilizer, agrochemical) being applied by the implement at the time of the reading, in the unit defined by the active VRA prescription. Supports compliance verification against prescribed rates and MRL (Maximum Residue Limit) audit trails.',
    `application_rate_target` DECIMAL(18,2) COMMENT 'Prescribed target rate of material application from the active VRA prescription at the time of the reading, in the same unit as actual_application_rate. Enables deviation analysis between prescribed and actual application for compliance and agronomic reporting.',
    `application_rate_unit` STRING COMMENT 'Unit of measure for the actual and target application rate fields (e.g., kg/ha for fertilizer, L/ha for liquid agrochemicals, seeds/ha for planting). Ensures correct interpretation of application rate values across different implement types.. Valid values are `kg_per_ha|l_per_ha|seeds_per_ha|bu_per_ac|lbs_per_ac|other`',
    `coolant_temp_c` DECIMAL(18,2) COMMENT 'Engine coolant temperature in degrees Celsius at the time of the reading. Elevated values trigger predictive maintenance alerts and can indicate impending engine failure.',
    `data_source` STRING COMMENT 'Identifies the originating system or IoT platform that streamed this telemetry record. EVENT_TYPE_OR_CHANNEL per EVENT_LOG role minimum. Supports multi-source fleet management and data lineage.. Valid values are `john_deere_ops_center|trimble_ag|climate_fieldview|granular|other`',
    `dtc_code` STRING COMMENT 'Diagnostic Trouble Code (DTC) reported by the equipments onboard diagnostics system at the time of the reading. Null when no fault is active. Triggers corrective maintenance work orders in SAP S/4HANA PM and supports predictive maintenance analytics.',
    `dtc_severity` STRING COMMENT 'Severity classification of the active Diagnostic Trouble Code (DTC) at the time of the reading. Critical faults require immediate equipment shutdown; warning faults require scheduled maintenance; informational faults are advisory only.. Valid values are `critical|warning|informational`',
    `engine_hours` DECIMAL(18,2) COMMENT 'Cumulative engine operating hours recorded on the equipments hour meter at the time of the reading. Primary trigger metric for preventive maintenance scheduling (PM) and asset lifecycle management per ISO 55000.',
    `engine_load_pct` DECIMAL(18,2) COMMENT 'Engine load as a percentage of maximum rated capacity at the time of the reading. Supports OEE calculation, fuel consumption benchmarking, and predictive maintenance triggers.',
    `engine_rpm` STRING COMMENT 'Engine speed in revolutions per minute at the time of the reading. Used for fuel efficiency analysis, operator behavior monitoring, and predictive maintenance trigger evaluation.',
    `field_boundary_match` BOOLEAN COMMENT 'Indicates whether the equipments GPS position at the time of the reading falls within the registered boundary of the assigned field. False values indicate potential off-field operation, boundary drift, or GPS error.',
    `fuel_consumption_rate_lph` DECIMAL(18,2) COMMENT 'Instantaneous fuel consumption rate in liters per hour at the time of the reading. Supports OPEX cost allocation, carbon footprint reporting, and fuel efficiency benchmarking across the fleet.',
    `fuel_level_pct` DECIMAL(18,2) COMMENT 'Remaining fuel level in the equipments tank expressed as a percentage of full capacity at the time of the reading. Supports dispatch planning, refueling logistics, and downtime prevention.',
    `gps_altitude_m` DOUBLE COMMENT 'Altitude of the equipment above mean sea level in meters at the time of the reading, as reported by the onboard GPS/RTK receiver. Supports terrain-aware precision agriculture analytics.',
    `ground_speed_kph` DECIMAL(18,2) COMMENT 'Actual ground speed of the equipment in kilometers per hour as measured by the GPS receiver at the time of the reading. Used for field coverage rate calculations, operator compliance, and OEE analysis.',
    `heading_degrees` DECIMAL(18,2) COMMENT 'Direction of travel of the equipment in degrees from true north (0–360) at the time of the reading. Supports field pass mapping, coverage analysis, and auto-steer validation.',
    `hydraulic_pressure_kpa` DECIMAL(18,2) COMMENT 'Hydraulic system pressure in kilopascals at the time of the reading. Abnormal values indicate hydraulic system faults and trigger corrective maintenance work orders.',
    `implement_depth_cm` DECIMAL(18,2) COMMENT 'Working depth of the attached implement (e.g., planter, tillage tool) in centimeters at the time of the reading. Supports agronomic compliance verification, VRA prescription audit trails, and soil management analytics.',
    `implement_width_m` DECIMAL(18,2) COMMENT 'Working width of the attached implement in meters at the time of the reading. Used for field coverage area calculations and pass efficiency analysis.',
    `ingested_timestamp` TIMESTAMP COMMENT 'The UTC timestamp when this telemetry record was received and ingested into the lakehouse Silver layer from the source system (John Deere Operations Center, Trimble, or other IoT platform). Supports data latency monitoring and pipeline auditing.',
    `latitude` DOUBLE COMMENT 'RTK-corrected WGS84 latitude coordinate of the equipment at the time of the reading, in decimal degrees. Supports fleet position tracking, field coverage monitoring, geofence evaluation, and theft detection.',
    `load_weight_kg` DECIMAL(18,2) COMMENT 'Weight of the load carried by the equipment (e.g., grain in combine hopper, fertilizer in applicator) in kilograms at the time of the reading. Supports yield estimation, logistics planning, and axle load compliance.',
    `longitude` DOUBLE COMMENT 'RTK-corrected WGS84 longitude coordinate of the equipment at the time of the reading, in decimal degrees. Supports fleet position tracking, field coverage monitoring, geofence evaluation, and theft detection.',
    `ndvi_reading` DECIMAL(18,2) COMMENT 'Normalized Difference Vegetation Index value captured by the onboard crop sensor at the time of the reading, ranging from -1.0 to 1.0. Supports variable rate application (VRA) decisions, crop health monitoring, and precision agriculture analytics.',
    `operational_status` STRING COMMENT 'Current operational state of the equipment at the time of the reading. Drives OEE (Overall Equipment Effectiveness) calculation by classifying time into productive, transport, idle, and parked categories. EVENT_PAYLOAD_OR_VALUE per EVENT_LOG role minimum.. Valid values are `field_working|transport|idle|parked|fault`',
    `pto_engaged` BOOLEAN COMMENT 'Indicates whether the Power Take-Off (PTO) shaft was engaged at the time of the reading. PTO engagement signals active implement operation (e.g., mower, spreader, pump) and is used for productive-time classification in OEE calculations.',
    `pto_rpm` STRING COMMENT 'Power Take-Off shaft speed in revolutions per minute at the time of the reading when PTO is engaged. Used to verify correct implement operating speed and diagnose PTO-related faults.',
    `reading_quality_flag` STRING COMMENT 'Data quality classification for this telemetry record assigned during Silver layer ingestion. Valid records are used in analytics; suspect records require review; invalid records are excluded from reporting. Supports data governance and AI/ML feature engineering.. Valid values are `valid|suspect|invalid`',
    `reading_timestamp` TIMESTAMP COMMENT 'The precise UTC timestamp when the telemetry event was recorded by the equipments onboard controller. EVENT_TIMESTAMP per EVENT_LOG role minimum. Distinct from ingestion audit timestamps.',
    `rtk_correction_status` STRING COMMENT 'Quality indicator for the GPS/RTK positional correction applied at the time of the reading. Fixed indicates sub-inch accuracy; float and dgps indicate degraded precision. Critical for VRA prescription audit trails and auto-steer accuracy validation.. Valid values are `fixed|float|dgps|autonomous|unavailable`',
    `signal_strength_dbm` DECIMAL(18,2) COMMENT 'Cellular or satellite communication signal strength in decibel-milliwatts (dBm) at the time of the reading. Supports data quality assessment, connectivity gap analysis, and telematics infrastructure planning.',
    `transmission_delay_ms` STRING COMMENT 'Latency in milliseconds between the equipment recording the telemetry event and the data being received by the cloud platform. Supports data quality scoring and near-real-time fleet dashboard reliability assessment.',
    CONSTRAINT pk_telematics_reading PRIMARY KEY(`telematics_reading_id`)
) COMMENT 'High-frequency telemetry records streamed from John Deere Operations Center, Trimble, and other IoT-enabled agricultural equipment. Captures machine hours, engine RPM, fuel consumption rate, ground speed, PTO engagement, hydraulic pressure, GPS coordinates (RTK-corrected latitude/longitude), heading, NDVI sensor readings, implement depth/width, load weight, fault codes (DTC), operational status (field working/transport/idle/parked), geofence zone, RTK correction status, field boundary match flag, data source identifier, and timestamp. SSOT for all equipment telemetry including fleet position tracking — latest-reading queries provide current fleet position for dispatch dashboards, field coverage monitoring, theft detection, and operator hours-of-service compliance (replacing standalone fleet_position). Supports OEE calculation, predictive maintenance triggers, precision agriculture VRA audit trails, and fleet dispatch. One record per telemetry event per asset.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`work_order` (
    `work_order_id` BIGINT COMMENT 'Unique surrogate identifier for the maintenance work order record in the CMMS (SAP PM). Primary key for the work_order data product.',
    `asset_id` BIGINT COMMENT 'Reference to the agricultural equipment or fleet asset (tractor, combine, planter, sprayer, irrigation system) against which this work order is raised. Links to the equipment asset master. Maps to SAP PM Functional Location or Equipment Number (EQUNR).',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP CO cost center to which OPEX maintenance costs (labor, parts, services) are allocated. Enables maintenance cost analysis by crop enterprise, field, or operational division. Maps to SAP CO Cost Center (KOSTL).',
    `employee_id` BIGINT COMMENT 'Reference to the primary maintenance technician or mechanic assigned to execute the work order. Used for labor scheduling, skill matching, and workforce productivity reporting. Maps to SAP PM Responsible Person (VAPLZ) and SAP SuccessFactors employee record.',
    `facility_id` BIGINT COMMENT 'Reference to the functional location (field, barn, workshop, irrigation zone) where the maintenance activity is performed. Supports geographic cost allocation and field-level maintenance analytics. Maps to SAP PM Functional Location (TPLNR).',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Maintenance work orders post parts, labor, and external service costs to specific GL accounts (e.g., repairs & maintenance expense, spare parts COGS). Agriculture finance requires GL account assignmen',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Regulatory agency inspections of farm equipment frequently mandate corrective maintenance work orders. Linking work_order to inspection_record enables tracing remediation work back to the regulatory i',
    `maintenance_plan_id` BIGINT COMMENT 'Reference to the preventive maintenance plan or task list that generated this work order (applicable for PM-type orders). Links scheduled maintenance cycles to executed work orders for compliance and interval tracking. Maps to SAP PM Maintenance Plan (WARPL).',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: Work order parts specification: a work order identifies the primary material/part required for the repair or service task. Linking to material_master enables parts availability checking at work order ',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: Work orders generated to fulfill regulatory maintenance requirements (OSHA-mandated repairs, EPA equipment upgrades, DOT-required fixes) must reference the compliance obligation that triggered them. E',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Maintenance work orders for regulated activities (chemical wash bays, CAFO equipment, spray rig servicing) must reference the governing permit. Enables permit-linked maintenance scheduling, regulatory',
    `purchase_requisition_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_requisition. Business justification: When a work order identifies required parts or external services, a purchase requisition is raised as the originating procurement document. Agriculture equipment managers trace work_order → purchase_r',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Work orders for external maintenance services (dealer repairs, specialist contractors) are executed by procurement vendors. The work_order has external_service_cost indicating vendor involvement. Link',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Storm damage and weather-triggered maintenance work orders (freeze damage, flood damage, lightning strikes) require linking to the specific weather observation that caused or coincided with the fault ',
    `work_center_id` BIGINT COMMENT 'SAP PM work center (workshop or maintenance crew) responsible for executing the work order. Used for capacity planning, labor scheduling, and cost rate determination. Maps to SAP PM Main Work Center (ARBPL).',
    `actual_end_timestamp` TIMESTAMP COMMENT 'Actual date and time when maintenance work was completed and the equipment was returned to service. Used to calculate MTTR, downtime duration, and OEE impact. Maps to SAP PM Actual Finish Date/Time (IDAT3/IUZEIT2).',
    `actual_labor_hours` DECIMAL(18,2) COMMENT 'Actual number of labor hours recorded against the work order upon completion. Used for OPEX cost tracking, technician productivity analysis, and variance reporting against planned hours. Maps to SAP PM Actual Work (ISMNW).',
    `actual_start_timestamp` TIMESTAMP COMMENT 'Actual date and time when maintenance work physically commenced on the equipment. Used to calculate response time, schedule adherence, and Mean Time to Repair (MTTR). Maps to SAP PM Actual Start Date/Time (IDAT2/IUZEIT).',
    `breakdown_indicator` BOOLEAN COMMENT 'Flag indicating whether this work order was triggered by an unplanned equipment breakdown (True) versus a scheduled maintenance activity (False). Drives MTBF calculations and reliability analytics. Maps to SAP PM Breakdown Indicator (MSAUS).',
    `completion_notes` STRING COMMENT 'Free-text technician notes recorded at work order completion describing the root cause identified, corrective actions taken, and any follow-up recommendations. Supports knowledge management and recurring fault analysis. Maps to SAP PM Technical Findings (LTXT).',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when the work order record was first created in the CMMS (SAP PM). Audit trail field for record lineage and SLA response time measurement. Maps to SAP PM Creation Date/Time (ERDAT/ERUHR).',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary cost fields on the work order (e.g., USD). Supports multi-currency operations for international agricultural enterprises. Maps to SAP FI currency key (WAERS).. Valid values are `^[A-Z]{3}$`',
    `equipment_downtime_hours` DECIMAL(18,2) COMMENT 'Total hours the equipment asset was unavailable for field operations due to this maintenance event. Critical input for OEE (Overall Equipment Effectiveness) calculation and harvest/planting window impact analysis. Maps to SAP PM Breakdown Duration.',
    `external_service_cost` DECIMAL(18,2) COMMENT 'Total monetary cost of external contractor or third-party service charges applied to the work order (e.g., OEM dealer service, specialist repair). Supports make-vs-buy analysis and total maintenance cost reporting. Maps to SAP PM external service orders (PM03).',
    `fault_code` STRING COMMENT 'Standardized equipment fault or failure code from the CMMS fault code catalogue (e.g., SAP PM Damage Code or John Deere diagnostic trouble code). Enables structured failure mode analysis, MTBF calculations, and reliability reporting. Maps to SAP PM Damage Code (QMCOD).',
    `fault_description` STRING COMMENT 'Free-text narrative describing the reported equipment fault, defect, or maintenance requirement as entered by the operator or maintenance planner. Supports root cause analysis and failure mode trending. Maps to SAP PM Malfunction Description (QMTXT).',
    `labor_cost` DECIMAL(18,2) COMMENT 'Total monetary cost of labor charged to the work order, calculated from actual labor hours multiplied by the applicable labor rate. Contributes to total maintenance OPEX. Maps to SAP CO actual cost settlement for labor activity type.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when the work order record was most recently modified in the CMMS. Supports incremental data pipeline processing in the Databricks Silver Layer and audit trail requirements. Maps to SAP PM Change Date (AEDAT).',
    `maintenance_plant` STRING COMMENT 'SAP organizational unit (plant code) responsible for executing the maintenance work order. Determines the maintenance workshop, spare parts inventory, and labor pool. Maps to SAP PM Maintenance Plant (SWERK).',
    `next_due_date` DATE COMMENT 'Calculated date when the next scheduled maintenance activity is due for this asset based on the PM plan interval or counter reading. Supports proactive maintenance scheduling and equipment availability planning. Maps to SAP PM Next Planned Date.',
    `order_number` STRING COMMENT 'Externally-known alphanumeric identifier for the work order as assigned by the CMMS (SAP PM). Used for cross-system reference, technician communication, and audit trails. Maps to SAP PM Order Number (AUFNR).. Valid values are `^WO-[0-9]{8,12}$`',
    `order_status` STRING COMMENT 'Current lifecycle state of the work order within the CMMS workflow. Drives operational dashboards, KPI reporting, and SLA compliance tracking. Maps to SAP PM system status (STAT). Values: open, in_progress, completed, cancelled, on_hold.. Valid values are `open|in_progress|completed|cancelled|on_hold`',
    `order_type` STRING COMMENT 'Classification of the maintenance work order by activity type: PM (Preventive Maintenance), CM (Corrective Maintenance), INSP (Inspection), CALIB (Calibration), OVERHAUL, or SAFETY. Drives scheduling logic, cost allocation, and OPEX reporting. Maps to SAP PM Order Type (AUART). [ENUM-REF-CANDIDATE: PM|CM|INSP|CALIB|OVERHAUL|SAFETY — promote to reference product]. Valid values are `PM|CM|INSP|CALIB|OVERHAUL|SAFETY`',
    `parts_line_count` STRING COMMENT 'Total number of spare parts or material consumption line items recorded against this work order. Provides a quick header-level indicator of parts complexity and supports inventory replenishment trigger logic without requiring line-level joins.',
    `planned_end_date` DATE COMMENT 'Scheduled date on which maintenance work is planned to be completed. Used for downtime window management, equipment availability planning, and SLA target setting. Maps to SAP PM Scheduled Finish Date (GLTRP).',
    `planned_labor_hours` DECIMAL(18,2) COMMENT 'Estimated number of labor hours required to complete the maintenance work order, as planned by the maintenance scheduler. Used for workforce capacity planning and budget forecasting. Maps to SAP PM Planned Work (ARBEI).',
    `planned_start_date` DATE COMMENT 'Scheduled date on which maintenance work is planned to commence, as set by the maintenance planner. Used for resource scheduling, parts pre-staging, and downtime planning. Maps to SAP PM Scheduled Start Date (GSTRP).',
    `priority_code` STRING COMMENT 'Numeric priority ranking assigned to the work order indicating urgency and scheduling precedence. 1=Emergency/Critical, 2=High, 3=Medium, 4=Low/Routine. Drives resource allocation and response time SLAs. Maps to SAP PM Priority (PRIOK).. Valid values are `1|2|3|4`',
    `reported_timestamp` TIMESTAMP COMMENT 'Date and time when the equipment fault or maintenance requirement was first reported by the operator or detected by telematics (John Deere Operations Center). Principal business event timestamp for the work order lifecycle. Maps to SAP PM Malfunction Start Date/Time (QMDAT/QMZEIT).',
    `safety_permit_number` STRING COMMENT 'Reference number of the safety permit (lock-out/tag-out, confined space, hot work) issued for this maintenance work order. Required for OSHA compliance documentation and safety audit trails.',
    `safety_permit_required` BOOLEAN COMMENT 'Flag indicating whether a safety permit (e.g., lock-out/tag-out, confined space entry, chemical handling permit) is required before maintenance work can commence. Supports OSHA compliance and safety management workflows.',
    `sign_off_timestamp` TIMESTAMP COMMENT 'Date and time when the work order was formally signed off and closed by the authorizing supervisor. Marks the official end of the work order lifecycle and triggers cost settlement in SAP CO.',
    `signed_off_by` STRING COMMENT 'Name or employee identifier of the supervisor or maintenance manager who formally approved and closed the work order. Required for quality assurance, regulatory compliance, and audit trail purposes. Maps to SAP PM Completed By (ERNAM).',
    `total_maintenance_cost` DECIMAL(18,2) COMMENT 'Total OPEX cost of the work order encompassing labor, parts, and external service charges. SSOT for maintenance cost reporting by asset, cost center, and crop enterprise. Maps to SAP CO total actual costs settled to the maintenance order (TKOSTEN).',
    CONSTRAINT pk_work_order PRIMARY KEY(`work_order_id`)
) COMMENT 'Corrective and preventive maintenance work orders for agricultural equipment managed through CMMS (e.g., SAP PM). Header captures work order number, order type (PM/CM/inspection), priority, asset reference, fault description, reported fault code, assigned technician, planned and actual start/end dates, labor hours, total maintenance cost (OPEX), work order status (open/in-progress/completed/cancelled), and sign-off details. Embedded parts consumption line items (replacing standalone parts_usage) capture part number, quantity used, unit cost, total cost, issue date, issuing warehouse/bin, and technician ID — SSOT for actual material consumption data supporting OPEX cost tracking, inventory replenishment triggers, and maintenance cost analysis by asset and crop enterprise. Core CMMS transactional record for all maintenance activities. Integrates with SAP MM goods issue and SAP CO cost allocation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`maintenance_plan` (
    `maintenance_plan_id` BIGINT COMMENT 'Unique system-generated identifier for the preventive maintenance (PM) plan record. Primary key for the maintenance_plan entity within the equipment domain SSOT.',
    `asset_category_id` BIGINT COMMENT 'Foreign key linking to equipment.asset_category. Business justification: maintenance_plan currently stores asset_category as a free-text STRING column, which is a denormalized reference to the asset_category lookup table. PM schedules in agricultural CMMS are defined at th',
    `asset_id` BIGINT COMMENT 'Reference to the specific equipment asset this plan is assigned to, when the plan is asset-specific rather than category-wide. Links to the equipment asset master record in the CMMS/SAP PM module.',
    `climate_normal_id` BIGINT COMMENT 'Foreign key linking to weather.climate_normal. Business justification: Seasonal maintenance plan intervals are calibrated against historical climate normals — average first frost dates drive winterization PM schedules, historical dust/humidity normals set filter replacem',
    `climate_risk_indicator_id` BIGINT COMMENT 'Foreign key linking to weather.climate_risk_indicator. Business justification: Seasonal PM plans for agricultural equipment are adjusted based on climate risk indicators — drought conditions increase dust filter intervals, freeze risk drives winterization schedules. The maintena',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: HACCP plans mandate equipment maintenance as prerequisite programs (PRPs) under FSMA Preventive Controls. Linking maintenance plans to the governing HACCP plan enables auditors to verify PRP complianc',
    `material_master_id` BIGINT COMMENT 'Foreign key linking to inventory.material_master. Business justification: MRO inventory planning: maintenance plans specify required materials (filters, lubricants, belts) that must be stocked. Linking maintenance_plan to material_master enables automated reorder triggering',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: EPA and OSHA regulations mandate specific maintenance intervals for agricultural equipment (pesticide applicator calibration, CAFO equipment inspections). Linking maintenance_plan to compliance_obliga',
    `vendor_contract_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor_contract. Business justification: Preventive maintenance plans in agriculture are often governed by OEM dealer service contracts or extended warranty agreements. Linking maintenance_plan to vendor_contract enables contract-driven PM s',
    `work_center_id` BIGINT COMMENT 'Reference to the SAP PM work center (maintenance shop, field service team, or external contractor) responsible for executing this maintenance plan. Drives labor cost allocation and scheduling.',
    `approved_by` STRING COMMENT 'Name or employee identifier of the maintenance manager or engineer who formally approved this maintenance plan for use. Required for regulatory compliance documentation under OSHA and EPA frameworks.',
    `approved_date` DATE COMMENT 'Date on which this maintenance plan was formally approved by the responsible maintenance manager or engineer. Establishes the official activation baseline for compliance and audit purposes.',
    `auto_wo_generation` BOOLEAN COMMENT 'Indicates whether this maintenance plan is configured to automatically generate work orders in SAP PM when the maintenance cycle due date or usage threshold is reached. When False, work orders must be created manually.',
    `cmms_plan_reference` STRING COMMENT 'External reference identifier linking this plan to the corresponding maintenance plan record in the CMMS (Computerized Maintenance Management System), such as SAP PM maintenance plan number or John Deere Operations Center service plan ID. Enables cross-system traceability.',
    `cost_center_code` STRING COMMENT 'SAP CO cost center code to which OPEX maintenance costs for this plan are allocated. Enables financial reporting of maintenance expenditure by farm unit, equipment type, or operational division.. Valid values are `^CC-[A-Z0-9]{4,10}$`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this maintenance plan record was first created in the system. Supports audit trail, data lineage, and compliance reporting requirements.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values in this plan (e.g., USD, EUR, BRL). Supports multi-currency operations for international agricultural enterprises.. Valid values are `^[A-Z]{3}$`',
    `effective_from` DATE COMMENT 'Date from which this maintenance plan becomes active and eligible to generate work orders. Aligns with asset commissioning date or seasonal equipment activation.',
    `effective_until` DATE COMMENT 'Date on which this maintenance plan expires or is decommissioned. Null indicates an open-ended plan with no scheduled end. Used for asset lifecycle management and plan version control.',
    `epa_compliance_required` BOOLEAN COMMENT 'Indicates whether this maintenance plan includes tasks subject to EPA regulatory requirements (e.g., sprayer calibration for pesticide application equipment, emissions checks, fluid disposal). Triggers environmental compliance documentation.',
    `estimated_labor_cost` DECIMAL(18,2) COMMENT 'Estimated total labor cost to execute one cycle of this maintenance plan, in the base currency. Calculated from estimated_labor_hours and applicable labor rates. Supports OPEX cost allocation.',
    `estimated_labor_hours` DECIMAL(18,2) COMMENT 'Total standard labor hours required to complete all tasks in this maintenance plan. Aggregated from individual task labor hour estimates. Used for workforce planning and OPEX budgeting.',
    `last_completed_date` DATE COMMENT 'Date the most recent maintenance cycle was completed and signed off. Used to calculate next_due_date and track compliance with PM schedules.',
    `last_completed_hours` DECIMAL(18,2) COMMENT 'Engine/operating hour meter reading at the time the most recent maintenance cycle was completed. Sourced from John Deere Operations Center telematics. Used for usage-based interval tracking.',
    `lead_time_days` STRING COMMENT 'Number of calendar days before the maintenance due date that a work order should be automatically generated, allowing time for parts procurement and labor scheduling. Supports seasonal readiness for planting and harvest windows.',
    `maintenance_cycle_unit` STRING COMMENT 'Unit of measure for the maintenance cycle interval. hours refers to engine/operating hours from John Deere Operations Center telematics; acres/hectares refer to field coverage metrics; calendar units support time-based strategies. [ENUM-REF-CANDIDATE: hours|days|weeks|months|years|acres|hectares|kilometers — 8 candidates stripped; promote to reference product]',
    `maintenance_cycle_value` DECIMAL(18,2) COMMENT 'Numeric interval defining how frequently the maintenance plan recurs. Interpreted in conjunction with maintenance_cycle_unit (e.g., 250 engine hours, 12 months, 500 acres). Sourced from OEM specifications and SAP PM maintenance strategy.',
    `next_due_date` DATE COMMENT 'Calculated date when the next maintenance cycle is due based on last completion and the maintenance cycle interval. Drives scheduling dashboards and work order auto-generation in SAP PM.',
    `next_due_hours` DECIMAL(18,2) COMMENT 'Engine/operating hour threshold at which the next maintenance cycle is due. Calculated as last_completed_hours plus the usage-based cycle interval. Sourced from John Deere Operations Center telematics data.',
    `oem_service_bulletin` STRING COMMENT 'Original Equipment Manufacturer (OEM) service bulletin or technical service document number that this maintenance plan is based on or references (e.g., John Deere Technical Manual TM-XXXX). Ensures alignment with manufacturer specifications.',
    `osha_compliance_required` BOOLEAN COMMENT 'Indicates whether this maintenance plan includes tasks subject to OSHA regulatory requirements (e.g., lockout/tagout procedures, confined space entry, hazardous energy control). Triggers mandatory safety documentation on generated work orders.',
    `plan_name` STRING COMMENT 'Human-readable descriptive name for the maintenance plan (e.g., Annual Combine Harvester PM, 250-Hour Tractor Engine Service). Used in operator dashboards and scheduling reports.',
    `plan_number` STRING COMMENT 'Externally-known alphanumeric identifier for the maintenance plan, used in CMMS work order generation, SAP PM module references, and cross-system communication. Follows the PM-XXXXXX naming convention.. Valid values are `^PM-[A-Z0-9]{4,20}$`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the maintenance plan. draft indicates plan is under development; active means plan is in use and generating work orders; suspended means temporarily paused; completed means all cycles fulfilled; cancelled means plan is no longer applicable.. Valid values are `draft|active|suspended|completed|cancelled`',
    `plan_version` STRING COMMENT 'Version number of the maintenance plan document (e.g., 1.0, 2.3). Incremented when plan tasks, intervals, or compliance requirements are revised. Supports audit trail and change management per ISO 55000.. Valid values are `^[0-9]+.[0-9]+$`',
    `precision_ag_hardware` BOOLEAN COMMENT 'Indicates whether this maintenance plan includes calibration or servicing tasks for precision agriculture hardware such as GPS/RTK receivers, VRA controllers, NDVI sensors, or auto-steer systems. Triggers specialized calibration task workflows.',
    `rei_hours` DECIMAL(18,2) COMMENT 'Restricted Entry Interval in hours applicable to maintenance tasks performed on sprayer or pesticide application equipment. Specifies the minimum time after pesticide application before maintenance personnel may safely enter treated areas. Mandated by EPA/FIFRA.',
    `required_skill_level` STRING COMMENT 'Minimum skill level required to execute the maintenance plan tasks. operator indicates basic tasks performable by equipment operators; certified_mechanic requires OEM-certified technicians. Drives workforce assignment in SAP SuccessFactors.. Valid values are `operator|technician|specialist|certified_mechanic`',
    `required_tools` STRING COMMENT 'Comma-separated list or description of specialized tools and equipment required to execute the maintenance plan tasks (e.g., torque wrench, hydraulic press, RTK calibration kit, diagnostic scanner). Supports tool reservation and kitting.',
    `safety_precautions` STRING COMMENT 'Free-text description of mandatory safety precautions required before and during execution of maintenance tasks in this plan (e.g., lockout/tagout procedures, PPE requirements, confined space protocols, chemical handling). Referenced in generated work orders.',
    `season_type` STRING COMMENT 'Agricultural season associated with this maintenance plan when seasonal_flag is True. Drives scheduling alignment with the crop calendar to ensure equipment is ready for critical operational windows.. Valid values are `pre_planting|post_planting|pre_harvest|post_harvest|winter_storage|annual`',
    `seasonal_flag` BOOLEAN COMMENT 'Indicates whether this maintenance plan is tied to a specific agricultural season (e.g., pre-planting inspection, post-harvest winterization). When True, scheduling is aligned with the crop calendar to ensure equipment readiness.',
    `strategy_type` STRING COMMENT 'Classification of the maintenance strategy driving this plan. time_based triggers on calendar intervals (e.g., annually); usage_based triggers on engine hours or acreage; condition_based triggers on sensor thresholds (e.g., oil pressure); predictive uses IoT/telematics analytics from John Deere Operations Center.. Valid values are `time_based|usage_based|condition_based|predictive`',
    `task_count` STRING COMMENT 'Total number of individual maintenance task line items defined within this plan (e.g., lubrication, filter replacement, calibration, inspection). Provides a quick summary of plan complexity for scheduling and labor estimation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this maintenance plan record. Used for change tracking, data synchronization, and audit trail maintenance in the Databricks Silver Layer.',
    CONSTRAINT pk_maintenance_plan PRIMARY KEY(`maintenance_plan_id`)
) COMMENT 'Preventive maintenance (PM) schedules and plans for agricultural equipment assets. Header defines maintenance strategy (time-based, usage-based, condition-based), maintenance cycle (e.g., every 250 engine hours, annually), applicable asset categories, and compliance requirements (OSHA, EPA, local equivalents). Embedded task list line items (replacing standalone maintenance_item) specify individual maintenance tasks including task type (lubrication, calibration, filter replacement, inspection, adjustment), task description, standard labor hours, required skill level, safety precautions (REI/OSHA), required tools, required parts/materials with quantities, and completion status. SSOT for all PM task definitions and maintenance scheduling. Linked to CMMS maintenance plans. Drives automatic work order generation and ensures equipment readiness for planting and harvest seasons.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`fault` (
    `fault_id` BIGINT COMMENT 'Unique surrogate identifier for each equipment fault record in the silver layer lakehouse. Primary key for the equipment_fault data product. Entity role: TRANSACTION_HEADER — a discrete business event (fault occurrence) with its own lifecycle from detection through resolution.',
    `asset_id` BIGINT COMMENT 'Reference to the agricultural equipment asset (tractor, combine, planter, sprayer, irrigation system, etc.) that experienced the fault. Links to the equipment asset master record.',
    `employee_id` BIGINT COMMENT 'Reference to the equipment operator or field technician who reported the fault, when detection source is operator-reported. Links to the workforce/employee master. Supports PARTY_REFERENCE requirement for TRANSACTION_HEADER role.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Equipment faults occur during specific field operations (e.g., a combine breakdown during harvesting, a sprayer fault during application). equipment_fault has field_id but no FK to the specific field_',
    `event_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_event. Business justification: Equipment faults causing reportable environmental incidents (spills, emissions exceedances, pesticide drift events) generate compliance events requiring regulatory notification. Linking equipment_faul',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or land parcel where the equipment was operating at the time of fault detection. Supports geospatial analysis and field-level OEE impact assessment via Esri ArcGIS.',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Equipment faults (sprayer malfunction, harvester contamination, cold storage failure) directly cause product nonconformances including MRL exceedances and food safety incidents. This traceability link',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail and storm damage to field equipment requires linking the fault record to the specific precipitation event for insurance warranty claims and USDA disaster reporting. equipment_fault has is_warrant',
    `precision_device_id` BIGINT COMMENT 'Identifier of the onboard telematics unit (John Deere Operations Center MTG or equivalent) that transmitted the fault signal. Used for data lineage tracing from telematics source to fault record and for diagnosing telematics data quality issues.',
    `telematics_reading_id` BIGINT COMMENT 'Foreign key linking to equipment.telematics_reading. Business justification: An equipment fault detected via telematics should reference the specific telematics_reading record that triggered the DTC/fault detection. equipment_fault already has telematics_device_id (→ precision',
    `violation_record_id` BIGINT COMMENT 'Foreign key linking to compliance.violation_record. Business justification: Equipment faults causing environmental incidents (chemical spills, unauthorized discharges, pesticide drift) trigger regulatory violations. Linking equipment_fault to violation_record enables root cau',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Root cause analysis for field equipment faults requires correlating fault detection with concurrent weather conditions (extreme cold causing hydraulic failure, high humidity causing electrical faults)',
    `work_order_id` BIGINT COMMENT 'Reference to the SAP PM corrective maintenance work order created in response to this fault. Enables traceability from fault detection through corrective action completion.',
    `acres_lost` DECIMAL(18,2) COMMENT 'Estimated number of acres that could not be worked due to equipment downtime from this fault. Quantifies the production impact in the primary agricultural unit of measure. Used for OPEX impact analysis, crop planning adjustments, and insurance claims. Expressed in acres (US standard).',
    `actual_repair_cost_usd` DECIMAL(18,2) COMMENT 'Actual total cost in US dollars incurred to repair the fault, as confirmed upon SAP PM work order settlement. Includes labor hours, spare parts consumed, and external contractor charges. Used for OPEX reporting, cost center allocation, and maintenance budget variance analysis per GAAP/IFRS.',
    `corrective_action_taken` STRING COMMENT 'Description of the corrective maintenance action performed to resolve the fault, as recorded in the SAP PM work order completion. Includes parts replaced, adjustments made, software updates applied, or temporary workarounds implemented. Essential for maintenance history and warranty claims.',
    `cost_center_code` STRING COMMENT 'SAP CO cost center code to which the repair costs for this fault are allocated. Enables OPEX tracking by farm unit, operational division, or geographic region. Supports financial reporting under GAAP/IFRS and SOX internal controls.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the fault record was first created in the source system (SAP PM notification or John Deere Operations Center alert). Serves as the RECORD_AUDIT_CREATED field for data lineage and audit trail purposes in the Databricks silver layer.',
    `detection_source` STRING COMMENT 'Method by which the fault was first detected. Telematics = automatically detected via John Deere Operations Center or onboard ECU; Operator_Report = reported by equipment operator; Inspection = identified during scheduled preventive maintenance inspection; Sensor_Alert = triggered by IoT sensor threshold breach; Third_Party = reported by external service provider.. Valid values are `telematics|operator_report|inspection|sensor_alert|third_party`',
    `detection_timestamp` TIMESTAMP COMMENT 'The precise date and time when the fault was first detected, either by telematics system or reported by the operator. This is the principal real-world business event timestamp (BUSINESS_EVENT_TIMESTAMP). Used as the start reference for downtime duration calculations and OEE availability metrics.',
    `downtime_duration_minutes` STRING COMMENT 'Total duration of equipment downtime in minutes, calculated from downtime_start_timestamp to downtime_end_timestamp. Stored as a business field (not a real-time derived metric) once the fault is closed. Core input for OEE (Overall Equipment Effectiveness) availability calculations and reliability-centered maintenance (RCM) analysis.',
    `downtime_end_timestamp` TIMESTAMP COMMENT 'Date and time when the equipment was returned to operational service following corrective action. Null if the fault is still open or equipment has not yet been restored. Used with downtime_start_timestamp to calculate total downtime duration for OEE availability metrics.',
    `downtime_start_timestamp` TIMESTAMP COMMENT 'Date and time when the equipment became operationally unavailable due to the fault. May differ from detection_timestamp if the equipment continued limited operation after fault detection. Used directly in OEE availability calculations and production impact assessments.',
    `dtc_code` STRING COMMENT 'Standardized Diagnostic Trouble Code (DTC) as transmitted by the equipments onboard telematics system (John Deere Operations Center, SAE J1939 protocol). Identifies the specific electronic control unit (ECU) fault condition. Used for automated fault classification and RCM analysis.',
    `engine_hours_at_fault` DECIMAL(18,2) COMMENT 'Total cumulative engine hours recorded on the equipment at the time the fault occurred, as reported by the telematics system. Critical for condition-based maintenance (CBM) analysis, warranty validation, and mean time between failures (MTBF) calculations.',
    `equipment_type` STRING COMMENT 'Classification of the agricultural equipment type that experienced the fault. Enables fault trend analysis by equipment category and supports fleet-level OEE benchmarking. [ENUM-REF-CANDIDATE: tractor|combine|planter|sprayer|irrigation_system|harvester|tillage|other — promote to reference product]',
    `estimated_repair_cost_usd` DECIMAL(18,2) COMMENT 'Estimated total cost in US dollars to repair the fault, including labor, parts, and external service charges. Populated at fault creation for budget planning; updated with actuals upon work order completion. Supports OPEX cost allocation and maintenance budget management per GAAP/IFRS financial reporting.',
    `fault_category` STRING COMMENT 'High-level classification of the fault type used for reliability-centered maintenance (RCM) analysis and spare parts planning. [ENUM-REF-CANDIDATE: mechanical|electrical|hydraulic|software|structural|operator_error|unknown — promote to reference product]',
    `fault_description` STRING COMMENT 'Human-readable description of the equipment fault, breakdown, or abnormal condition. May be auto-populated from DTC lookup table or manually entered by the operator/technician. Provides context for maintenance planning and root cause analysis.',
    `fault_number` STRING COMMENT 'Externally-known business identifier for the fault record, used in maintenance work orders, operator reports, and SAP PM notifications. Format: EF-{YYYY}-{NNNNNN}. Serves as the human-readable reference across SAP S/4HANA PM, John Deere Operations Center, and field communications.. Valid values are `^EF-[0-9]{4}-[0-9]{6}$`',
    `fault_status` STRING COMMENT 'Current lifecycle status of the fault record from initial detection through resolution and closure. Drives workflow routing in SAP PM and maintenance scheduling. Open = detected, not yet actioned; In_Progress = corrective action underway; Resolved = fix applied; Closed = verified and closed; Recurring = fault has reoccurred after prior resolution.. Valid values are `open|in_progress|resolved|closed|recurring`',
    `gps_latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate (decimal degrees, WGS84) of the equipments location at the time of fault detection, as recorded by the onboard GPS/RTK receiver. Enables geospatial fault mapping in Esri ArcGIS and field-level downtime analysis.',
    `gps_longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate (decimal degrees, WGS84) of the equipments location at the time of fault detection, as recorded by the onboard GPS/RTK receiver. Used with gps_latitude for geospatial fault mapping and field-level impact analysis.',
    `is_safety_critical` BOOLEAN COMMENT 'Indicates whether the fault poses a safety risk to the equipment operator or bystanders. Safety-critical faults trigger mandatory OSHA incident reporting workflows and immediate equipment lockout/tagout (LOTO) procedures. True = safety risk present; False = no immediate safety concern.',
    `is_warranty_claim` BOOLEAN COMMENT 'Indicates whether this fault has been submitted or is eligible for a manufacturer warranty claim. True = warranty claim initiated or applicable; False = out-of-warranty or not eligible. Supports CAPEX/OPEX cost recovery tracking and vendor performance management.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to the fault record in the source system. Serves as the RECORD_AUDIT_UPDATED field for change tracking, incremental data pipeline processing, and audit trail compliance in the Databricks silver layer.',
    `maintenance_team` STRING COMMENT 'Name or code of the maintenance team or work center responsible for resolving this fault, as assigned in SAP PM. Examples: internal_fleet_team, dealer_service, oem_field_technician. Supports workload balancing and maintenance team performance KPI reporting.',
    `odometer_km_at_fault` DECIMAL(18,2) COMMENT 'Total cumulative distance in kilometers recorded on the equipment odometer at the time of fault, as reported by telematics. Applicable to mobile equipment (tractors, combines, sprayers). Used alongside engine hours for condition-based maintenance scheduling and warranty claims.',
    `recurrence_count` STRING COMMENT 'Number of times this same fault (same DTC code or fault category on the same asset) has recurred within the current operating season. A value greater than 1 indicates a recurring fault pattern requiring escalated RCM investigation. Supports chronic failure identification and maintenance strategy optimization.',
    `resolution_timestamp` TIMESTAMP COMMENT 'Date and time when the fault was confirmed as resolved and the equipment returned to full operational service. Distinct from downtime_end_timestamp (which marks when equipment restarted) — resolution_timestamp marks formal closure confirmation in SAP PM. Used for mean time to repair (MTTR) calculations.',
    `root_cause_code` STRING COMMENT 'Standardized root cause classification code assigned after fault investigation, aligned with SAP PM cause catalog and ISO 14224 failure taxonomy. Examples: wear_and_tear, improper_maintenance, manufacturing_defect, operator_misuse, environmental_damage, age_related_failure. Used for RCM analysis and preventive maintenance optimization. [ENUM-REF-CANDIDATE: wear_and_tear|improper_maintenance|manufacturing_defect|operator_misuse|environmental_damage|age_related_failure|unknown — promote to reference product]',
    `root_cause_description` STRING COMMENT 'Free-text narrative describing the identified root cause of the fault following investigation. Complements root_cause_code with detailed findings from the technician or maintenance engineer. Supports knowledge base development and recurring fault prevention.',
    `severity_level` STRING COMMENT 'Severity classification of the fault indicating operational impact and urgency of corrective action. Critical = immediate equipment stoppage; High = significant performance degradation; Medium = reduced efficiency; Low = minor issue, can continue operating. Drives maintenance prioritization and OEE availability calculations.. Valid values are `critical|high|medium|low`',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this fault record originated. SAP_PM = SAP S/4HANA Plant Maintenance notification; JD_OPS_CENTER = John Deere Operations Center telematics alert; TRIMBLE = Trimble Ag Software field report; MANUAL = manually entered; CLIMATE_FIELDVIEW = Climate FieldView event. Supports data lineage and silver layer reconciliation.. Valid values are `SAP_PM|JD_OPS_CENTER|TRIMBLE|MANUAL|CLIMATE_FIELDVIEW`',
    `yield_impact_bu` DECIMAL(18,2) COMMENT 'Estimated yield loss in bushels (BU) attributable to the equipment downtime caused by this fault. Calculated based on acres lost and expected yield per acre (YPM). Supports crop loss reporting, insurance claims, and financial impact assessment. BU (Bushel) is the standard grain yield unit per USDA WASDE reporting.',
    CONSTRAINT pk_fault PRIMARY KEY(`fault_id`)
) COMMENT 'Record of equipment faults, breakdowns, and diagnostic trouble codes (DTC) detected via telematics or reported by operators. Captures fault code, fault description, severity level, detection source (telematics/operator/inspection), asset affected, field/location at time of fault, downtime start/end, estimated production impact (acres lost, yield impact), root cause classification, and corrective action taken. Feeds into OEE availability calculations and reliability-centered maintenance (RCM) analysis.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`parts_inventory` (
    `parts_inventory_id` BIGINT COMMENT 'Unique surrogate identifier for each spare part or consumable record in the MRO (Maintenance, Repair, and Operations) inventory master. Primary key for the parts_inventory data product.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Parts inventory is physically stocked at specific facilities (maintenance shops co-located at grain elevators or processing plants). Linking parts_inventory to supply.facility enables inventory visibi',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Parts inventory valuation is posted to GL accounts (spare parts inventory asset account on receipt; maintenance expense on consumption). Agriculture operations require this for inventory balance sheet',
    `vendor_id` BIGINT COMMENT 'Reference to the primary vendor/supplier from whom this part is procured. Links to the supplier master for automated purchase requisition routing and supplier performance tracking in SAP MM procurement.',
    `abc_classification` STRING COMMENT 'ABC analysis classification of the part based on annual consumption value: A = high-value/high-priority (top 80% of spend), B = medium-value (next 15%), C = low-value (bottom 5%). Drives differentiated inventory control policies, cycle count frequencies, and safety stock levels in SAP MM.. Valid values are `A|B|C`',
    `annual_consumption_quantity` DECIMAL(18,2) COMMENT 'Total quantity of this part consumed in the trailing 12-month period, expressed in the base unit of measure. Used as the primary input for reorder point and safety stock calculations, and for identifying slow-moving inventory candidates for write-down.',
    `asset_class_code` STRING COMMENT 'SAP AM (Asset Management) asset class code indicating whether this part is capitalized as a CAPEX (Capital Expenditure) item or expensed as OPEX (Operational Expenditure). Drives accounting treatment and depreciation scheduling for high-value replacement components.',
    `bin_location` STRING COMMENT 'Specific bin, shelf, or rack location within the storage facility where this part is physically located (e.g., A-12-03 = Aisle A, Rack 12, Shelf 3). Managed by Manhattan Associates WMS for precise pick-and-put-away operations.',
    `compatible_asset_models` STRING COMMENT 'Comma-separated list of specific equipment model numbers or model families this part is compatible with (e.g., John Deere 8R 410, John Deere 8R 370, Case IH Magnum 380). Enables technicians to quickly identify applicable parts during field maintenance.',
    `cost_center_code` STRING COMMENT 'SAP CO (Controlling) cost center code to which the cost of this part is allocated when issued against a maintenance work order. Enables OPEX (Operational Expenditure) tracking by farm, equipment fleet, or business unit for financial reporting and budgeting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this parts inventory master record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail requirements and data lineage tracking per SOX internal controls.',
    `criticality_classification` STRING COMMENT 'Operational criticality rating of the part: critical (stockout causes immediate equipment downtime during planting or harvest), non_critical (equipment can operate temporarily without), or safety_critical (required for operator safety per OSHA standards). Drives safety stock levels and emergency procurement protocols.. Valid values are `critical|non_critical|safety_critical`',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code in which the unit cost and total stock value are denominated (e.g., USD, EUR, BRL). Supports multi-currency operations for global agricultural enterprises.. Valid values are `^[A-Z]{3}$`',
    `equipment_category` STRING COMMENT 'The primary agricultural equipment category this part is compatible with (e.g., tractor, combine, planter, sprayer, irrigation system). Supports parts lookup during maintenance planning and work order creation. [ENUM-REF-CANDIDATE: tractor|combine|planter|sprayer|irrigation|tillage|harvester|grain_cart|general — promote to reference product]',
    `hazardous_material_flag` BOOLEAN COMMENT 'Indicates whether this part or consumable is classified as a hazardous material requiring special storage, handling, or disposal procedures (e.g., hydraulic fluids, battery acid, pesticide concentrates). When True, triggers compliance with EPA and OSHA hazardous materials regulations and requires an associated Safety Data Sheet (SDS).',
    `inventory_status` STRING COMMENT 'Current lifecycle status of the part record in the inventory master: active (stocked and available), inactive (temporarily not stocked), obsolete (superseded by a newer part number), discontinued (no longer available from OEM), or on_order (replenishment in progress). Governs whether the part can be issued against work orders.. Valid values are `active|inactive|obsolete|discontinued|on_order`',
    `last_issued_date` DATE COMMENT 'Date on which this part was most recently issued from inventory to a maintenance work order or field technician. Used to identify slow-moving or obsolete inventory and support inventory rationalization decisions.',
    `last_physical_count_date` DATE COMMENT 'Date of the most recent physical inventory count or cycle count for this part. Used to assess inventory accuracy, identify shrinkage, and schedule next count per the annual physical inventory plan. Aligns with SAP MM inventory management cycle count functionality.',
    `last_receipt_date` DATE COMMENT 'Date of the most recent goods receipt (GRN) for this part from a supplier. Supports inventory freshness analysis, supplier delivery performance tracking, and shelf-life management for perishable consumables.',
    `lead_time_days` STRING COMMENT 'Standard procurement lead time in calendar days from purchase order (PO) placement to goods receipt (GRN) at the warehouse. Critical input for reorder point calculation to ensure parts availability during planting and harvest seasons.',
    `material_number` STRING COMMENT 'The SAP S/4HANA Material Management (MM) module material number uniquely identifying this spare part or consumable within the enterprise ERP system. Serves as the primary cross-system integration key for procurement, inventory, and maintenance workflows.',
    `maximum_stock_quantity` DECIMAL(18,2) COMMENT 'The upper inventory limit for this part, beyond which overstocking is flagged. Used in SAP MM min/max replenishment planning to prevent excess capital tied up in slow-moving MRO (Maintenance, Repair, and Operations) inventory.',
    `oem_part_number` STRING COMMENT 'The original equipment manufacturers (OEM) part number as published in the equipment service manual or parts catalog. Used for cross-referencing with supplier catalogs, warranty claims, and ordering from authorized dealers (e.g., John Deere, CNH Industrial, AGCO).',
    `part_category` STRING COMMENT 'High-level classification of the spare part by functional category. Drives inventory segmentation, procurement routing, and storage requirements. [ENUM-REF-CANDIDATE: mechanical|electrical|hydraulic|pneumatic|consumable|lubricant|filter|wear_part|structural|electronic — promote to reference product]',
    `part_description` STRING COMMENT 'Detailed technical description of the spare part including specifications, dimensions, material composition, and application context. Supports accurate identification during procurement and maintenance activities.',
    `part_name` STRING COMMENT 'Human-readable short name or title of the spare part or consumable (e.g., Air Filter Element, Hydraulic Pump Seal Kit, Combine Header Drive Belt). Used for display in work orders, purchase requisitions, and inventory reports.',
    `part_type` STRING COMMENT 'Distinguishes the nature of the inventory item: spare_part (replacement component), consumable (single-use item such as oil or filter), tool (maintenance tooling), assembly (multi-component unit), or sub_assembly (partial assembly). Drives MRO (Maintenance, Repair, and Operations) inventory policy and cost allocation between CAPEX and OPEX.. Valid values are `spare_part|consumable|tool|assembly|sub_assembly`',
    `plant_code` STRING COMMENT 'SAP organizational unit (plant code) representing the farm site, maintenance facility, or distribution center where this part inventory record is maintained. Enables multi-plant inventory management across geographically distributed agricultural operations.',
    `reorder_point` DECIMAL(18,2) COMMENT 'The minimum stock quantity threshold at which a replenishment purchase requisition is automatically triggered in SAP MM MRP (Material Requirements Planning). Calculated based on average daily consumption during peak seasons (planting/harvest) and supplier lead time to prevent equipment downtime.',
    `reorder_quantity` DECIMAL(18,2) COMMENT 'The standard replenishment order quantity triggered when stock falls to or below the reorder point. Optimized to balance procurement costs, storage capacity, and supplier minimum order quantities (MOQ). Drives automated purchase requisition creation in SAP MM.',
    `safety_stock_quantity` DECIMAL(18,2) COMMENT 'Buffer stock quantity maintained above the reorder point to absorb demand variability and supply disruptions during critical agricultural seasons (planting, harvest). Particularly important for critical-classified parts where stockout causes immediate equipment downtime.',
    `sds_document_number` STRING COMMENT 'Reference number for the Safety Data Sheet (SDS) associated with this hazardous part or consumable. Required by OSHA Hazard Communication Standard (HazCom) for all hazardous chemicals stored in the workplace. Null for non-hazardous parts.',
    `shelf_life_days` STRING COMMENT 'Maximum storage duration in days before the part or consumable degrades or expires (applicable to lubricants, chemicals, rubber seals, and other perishable MRO items). Null for non-perishable parts. Supports FEFO (First Expired First Out) inventory management.',
    `stock_quantity` DECIMAL(18,2) COMMENT 'Current on-hand stock quantity of the part expressed in the base unit of measure (UOM). Represents unrestricted-use stock available for maintenance work orders. Updated in real time via goods receipts (GRN) and goods issues from SAP MM or Manhattan Associates WMS.',
    `storage_location_code` STRING COMMENT 'SAP MM storage location code identifying the warehouse or farm facility where this part is physically stored (e.g., WH01 = Central Parts Warehouse, FRM-NORTH = North Farm Shop). Supports multi-site inventory management across farm operations.',
    `supplier_part_number` STRING COMMENT 'The suppliers own catalog or part number for this item, as used in purchase orders (PO) and goods receipt notes (GRN). Enables accurate ordering and receiving reconciliation with supplier invoices and packing lists.',
    `total_stock_value` DECIMAL(18,2) COMMENT 'Total monetary value of current on-hand stock, calculated as stock_quantity multiplied by unit_cost. Represents the balance sheet carrying value of MRO (Maintenance, Repair, and Operations) inventory for financial reporting under GAAP/IFRS. Refreshed upon each inventory transaction.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Standard or moving average cost per unit of measure for this part, expressed in the local currency. Used for inventory valuation, OPEX/CAPEX cost allocation to maintenance work orders, and total stock value calculation. Sourced from SAP MM material master valuation data.',
    `unit_of_measure` STRING COMMENT 'The base unit of measure (UOM) in which the part is stocked and transacted (e.g., EA = each, KG = kilogram, L = liter, M = meter, SET = set, BOX = box). Aligns with SAP MM base UOM configuration and drives quantity calculations for reorder and valuation. [ENUM-REF-CANDIDATE: EA|KG|L|M|SET|BOX|ROLL|PAIR|GAL — 9 candidates stripped; promote to reference product]',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this parts inventory master record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for incremental data pipeline processing (delta loads) and change audit trail in the Databricks Silver Layer.',
    `valuation_method` STRING COMMENT 'The cost accounting method used to value this parts inventory: standard_cost (fixed standard price), moving_average (weighted average updated on each receipt), fifo (first-in first-out), or lifo (last-in first-out). Configured in SAP MM material master and governs financial reporting treatment.. Valid values are `standard_cost|moving_average|fifo|lifo`',
    `warranty_period_months` STRING COMMENT 'OEM or supplier warranty duration in months from the date of installation or purchase. Supports warranty claim tracking and cost recovery from suppliers for premature part failures. Null if no warranty applies.',
    CONSTRAINT pk_parts_inventory PRIMARY KEY(`parts_inventory_id`)
) COMMENT 'Inventory master for spare parts, consumables, and replacement components held for agricultural equipment maintenance. Captures part number (material number), part description, OEM part number, compatible asset models/categories, unit of measure, current stock quantity, reorder point, reorder quantity, storage location (bin/warehouse), unit cost, total stock value, lead time from supplier, and criticality classification (critical/non-critical). Supports MRO (Maintenance, Repair, and Operations) inventory management, prevents equipment downtime due to parts stockouts during planting and harvest seasons, and integrates with procurement for automated replenishment.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`oee_record` (
    `oee_record_id` BIGINT COMMENT 'Unique surrogate identifier for each OEE measurement record. Primary key for the oee_record data product in the equipment domain Silver Layer.',
    `asset_assignment_id` BIGINT COMMENT 'Foreign key linking to equipment.asset_assignment. Business justification: OEE records measure equipment effectiveness per asset per shift, which directly corresponds to an asset_assignment period (equipment assigned to a field/operator/cost center). Linking oee_record to as',
    `asset_id` BIGINT COMMENT 'Reference to the agricultural equipment asset (tractor, combine, planter, sprayer, irrigation system, etc.) for which this OEE record is calculated. Links to the equipment asset master.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Agriculture OEE benchmarking is performed by commodity type — combine OEE for corn vs. soybeans differs by crop characteristics. Equipment performance reports segmented by commodity are standard in pr',
    `employee_id` BIGINT COMMENT 'Reference to the equipment operator (workforce member) responsible for operating the asset during this OEE measurement period. Supports operator performance benchmarking.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: OEE is measured for equipment operating at supply facilities (grain dryers, conveyors, elevators). Facility-level OEE reporting is a standard KPI in post-harvest operations. This link enables throughp',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or land parcel where the equipment was operating during this OEE measurement period. Enables spatial analysis of equipment performance by field zone using Esri ArcGIS and John Deere Operations Center field mapping.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season or crop year during which this OEE record was captured. Enables seasonal fleet performance trending and year-over-year OEE benchmarking aligned with crop planning cycles.',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: OEE records for harvest equipment measure actual throughput against contracted delivery volumes. Contract performance reporting uses OEE availability and throughput data to validate whether equipment ',
    `shift_id` BIGINT COMMENT 'Reference to the operational shift or work schedule period during which this OEE record was captured. Supports shift-level fleet performance analysis.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: OEE variance analysis for agricultural machinery requires separating weather-caused downtime (rain delays, extreme heat shutdowns) from mechanical downtime. Linking oee_record to the concurrent weathe',
    `acceptable_output_quantity` DECIMAL(18,2) COMMENT 'Quantity of output meeting quality standards during the measurement period. Used as the numerator for quality rate calculation. For harvesting equipment, represents grain meeting grade standards; for sprayers, represents correctly applied area.',
    `actual_operating_time_min` STRING COMMENT 'Total minutes the asset was actively operating (engine running and performing work) during the measurement period, as recorded by John Deere Operations Center telematics. Equals planned production time minus unplanned downtime.',
    `actual_throughput_rate` DECIMAL(18,2) COMMENT 'The measured actual throughput rate of the asset during operating time (e.g., acres per hour, gallons per minute). Compared against theoretical throughput rate to derive performance rate.',
    `availability_rate` DECIMAL(18,2) COMMENT 'Ratio of actual operating time to planned production time, expressed as a decimal (e.g., 0.9250 = 92.50%). Calculated as (Planned Production Time - Unplanned Downtime) / Planned Production Time. One of the three OEE component rates.',
    `breakdown_count` STRING COMMENT 'Number of unplanned equipment breakdowns (failures requiring corrective maintenance work orders) that occurred during the measurement period. Drives unplanned downtime and is a key input to MTBF calculation.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this OEE record was first created in the Silver Layer data product. Supports audit trail and data lineage tracking for the Databricks Lakehouse ingestion pipeline.',
    `data_source` STRING COMMENT 'Operational system of record from which the OEE measurement data was sourced. Supports data lineage tracking and audit trail for Silver Layer ingestion. Primary source is John Deere Operations Center telematics; secondary sources include SAP S/4HANA PM and manual entry.. Valid values are `john_deere_ops_center|sap_pm|manual_entry|trimble_ag|climate_fieldview`',
    `engine_hours` DECIMAL(18,2) COMMENT 'Total engine operating hours accumulated by the asset during the measurement period, as reported by John Deere Operations Center telematics. Used for preventive maintenance scheduling and asset lifecycle tracking per ISO 55000.',
    `fuel_consumption_gallons` DECIMAL(18,2) COMMENT 'Total fuel consumed by the asset during the measurement period in US gallons, as reported by John Deere Operations Center telematics. Used for OPEX cost allocation, fuel efficiency benchmarking, and environmental reporting.',
    `gps_tracking_enabled` BOOLEAN COMMENT 'Indicates whether GPS/RTK precision positioning was active on the asset during this measurement period. When true, telematics data (acres covered, field boundaries) is sourced from John Deere Operations Center GPS telemetry; when false, data may be manually entered.',
    `idle_time_min` STRING COMMENT 'Total minutes the asset engine was running but not performing productive work (idling) during the measurement period. Captured via John Deere Operations Center telematics. Contributes to performance loss analysis and fuel waste identification.',
    `measurement_date` DATE COMMENT 'The calendar date on which this OEE measurement was recorded. Used for daily and shift-level fleet performance trending and CAPEX justification reporting.',
    `measurement_end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the OEE measurement period ended (shift or day end). Combined with start timestamp to derive total measurement window duration.',
    `measurement_period_type` STRING COMMENT 'Granularity of the OEE measurement period: shift-level (per operational shift), daily (24-hour calendar day), or weekly (7-day rolling). Determines aggregation level for KPI reporting.. Valid values are `shift|daily|weekly`',
    `measurement_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the OEE measurement period began (shift or day start). Used for granular telematics alignment with John Deere Operations Center data.',
    `minor_stoppage_count` STRING COMMENT 'Number of brief, unplanned stoppages (typically under 10 minutes each) that did not trigger a formal work order but contributed to performance rate loss during the measurement period. Sourced from John Deere Operations Center telematics event data.',
    `oee_benchmark_target` DECIMAL(18,2) COMMENT 'The benchmark OEE target percentage (as a decimal) defined for the asset category (e.g., 0.8500 = 85% for combines). Sourced from asset category reference data. Used to assess performance gap and trigger CAPEX replacement reviews.',
    `oee_percentage` DECIMAL(18,2) COMMENT 'Composite OEE score expressed as a decimal (e.g., 0.7906 = 79.06%), calculated as Availability Rate × Performance Rate × Quality Rate. Primary KPI for fleet performance management and CAPEX justification for equipment replacement per ISO 55000.',
    `oee_variance` DECIMAL(18,2) COMMENT 'Difference between actual OEE percentage and the benchmark target (oee_percentage minus oee_benchmark_target), expressed as a signed decimal. Negative values indicate underperformance; used to prioritize maintenance interventions and CAPEX reviews.',
    `operation_type` STRING COMMENT 'Type of agricultural operation the equipment was performing during the measurement period. Enables OEE benchmarking by operation type (e.g., combine OEE during harvesting vs. transport). [ENUM-REF-CANDIDATE: planting|spraying|harvesting|tillage|irrigation|fertilization|transport|other — promote to reference product]',
    `output_unit` STRING COMMENT 'Unit of measure for total and acceptable output quantity fields. Aligned with asset type and crop/operation context. Examples: acres for field coverage, bushels (BU) or metric tons (MT) for harvested grain, gallons for applied inputs.. Valid values are `acres|bushels|metric_tons|gallons|cwt|loads`',
    `performance_rate` DECIMAL(18,2) COMMENT 'Ratio of actual throughput to theoretical maximum throughput during operating time, expressed as a decimal (e.g., 0.8800 = 88.00%). Captures speed losses and minor stoppages. One of the three OEE component rates.',
    `planned_downtime_min` STRING COMMENT 'Total minutes of scheduled downtime during the measurement period for preventive maintenance (PM), calibration, operator breaks, or planned changeovers. Excluded from planned production time per OEE methodology.',
    `planned_production_time_min` STRING COMMENT 'Total scheduled operating time in minutes for the asset during the measurement period, excluding planned maintenance windows and scheduled breaks. Denominator for availability rate calculation per OEE methodology.',
    `quality_rate` DECIMAL(18,2) COMMENT 'Ratio of acceptable output (meeting quality standards) to total output produced during the measurement period, expressed as a decimal (e.g., 0.9700 = 97.00%). Captures quality losses such as crop damage or mis-application. One of the three OEE component rates.',
    `record_number` STRING COMMENT 'Externally-known business identifier for this OEE measurement record, formatted as OEE-YYYY-MM-DD-XXXXXX. Used for cross-system referencing between SAP S/4HANA PM and John Deere Operations Center.. Valid values are `^OEE-[0-9]{4}-[0-9]{2}-[0-9]{2}-[A-Z0-9]{6}$`',
    `record_status` STRING COMMENT 'Current lifecycle status of the OEE record: draft (data being collected), confirmed (data validated by system), approved (reviewed by fleet manager), voided (record invalidated due to data quality issues).. Valid values are `draft|confirmed|approved|voided`',
    `theoretical_throughput_rate` DECIMAL(18,2) COMMENT 'The ideal or nameplate throughput rate of the asset under optimal conditions (e.g., acres per hour for a combine, gallons per minute for a sprayer). Used as the denominator for performance rate calculation.',
    `throughput_unit` STRING COMMENT 'Unit of measure for throughput rate fields (theoretical and actual), aligned with the asset type and operation. Examples: acres_per_hour for planters/combines, gallons_per_min for sprayers, bushels_per_hour for grain handling equipment.. Valid values are `acres_per_hour|gallons_per_min|bushels_per_hour|metric_tons_per_hour|loads_per_hour`',
    `total_acres_covered` DECIMAL(18,2) COMMENT 'Total land area covered by the equipment during the measurement period, in acres, as recorded by GPS/RTK telematics from John Deere Operations Center. Key operational metric for field coverage efficiency and fuel cost allocation.',
    `total_output_quantity` DECIMAL(18,2) COMMENT 'Total quantity of output produced by the asset during the measurement period (e.g., total acres covered, total bushels harvested, total gallons applied). Includes both acceptable and rejected/defective output.',
    `unplanned_downtime_min` STRING COMMENT 'Total minutes of unplanned equipment downtime during the measurement period due to breakdowns, failures, or unexpected stoppages. Key input to availability rate and MTBF/MTTR analysis per ISO 55000.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this OEE record was last modified in the Silver Layer data product. Used to detect late-arriving telematics data corrections from John Deere Operations Center and track record revision history.',
    `work_center_code` BIGINT COMMENT 'Reference to the SAP S/4HANA work center or operational unit (farm site, field zone, processing facility) where the equipment was deployed during this OEE measurement period.',
    CONSTRAINT pk_oee_record PRIMARY KEY(`oee_record_id`)
) COMMENT 'Overall Equipment Effectiveness (OEE) measurement records calculated per asset per operational shift or day. Captures availability rate (planned vs. actual uptime), performance rate (actual vs. theoretical throughput), quality rate (acceptable output vs. total output), composite OEE percentage, planned production time, unplanned downtime minutes, planned downtime minutes, total acres covered, and benchmark OEE target from asset category. Supports fleet performance management, CAPEX justification for equipment replacement, and operational efficiency KPI reporting aligned with ISO 55000.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`equipment_field_operation` (
    `equipment_field_operation_id` BIGINT COMMENT 'Unique surrogate identifier for each field-level equipment operation record in the Silver Layer lakehouse. Primary key for the field_operation data product.',
    `line_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice_line. Business justification: Custom hire field operations (spraying, harvesting, tillage) performed for third parties are billed line-by-line on AR invoices. Agriculture custom hire billing requires linking each invoiced line to ',
    `asset_assignment_id` BIGINT COMMENT 'Foreign key linking to equipment.asset_assignment. Business justification: field_operation records the actual execution of equipment work in the field, while asset_assignment is the governing planning record that authorizes equipment use for a specific field, operator, and c',
    `conservation_practice_id` BIGINT COMMENT 'Foreign key linking to land.conservation_practice. Business justification: Field operations implementing conservation practices (cover crop seeding, contour tillage, filter strip maintenance) must be linked to the NRCS conservation_practice record for cost-share payment docu',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Field operations (planting, spraying, harvesting) are executed by crews in agriculture. Linking field_operation to crew enables crew-level labor cost allocation, H2A compliance reporting by crew, and ',
    `employee_id` BIGINT COMMENT 'Reference to the workforce employee or contractor who performed the field operation. Used for labor cost allocation, operator certification compliance (OSHA, pesticide applicator licensing), and performance analytics.',
    `field_id` BIGINT COMMENT 'Reference to the specific field or parcel where the operation was conducted. Links to the land and soil domain for GIS-based spatial analysis, crop rotation planning, and GLOBALG.A.P. field registration.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which this operation was performed. Enables seasonal aggregation of as-applied records, yield correlation analysis, and crop plan compliance verification.',
    `input_catalog_id` BIGINT COMMENT 'Foreign key linking to procurement.input_catalog. Business justification: Field operations apply inputs defined in the input_catalog (PHI, REI, MRL, EPA registration). Linking field_operation to input_catalog enables real-time compliance verification of application rates ag',
    `input_product_id` BIGINT COMMENT 'Foreign key linking to product.input_product. Business justification: GAP/FIFRA compliance requires verifying REI hours, PHI days, and max application rate for each field operation. Direct FK to input_product enables compliance officers and agronomists to validate appli',
    `irrigation_zone_id` BIGINT COMMENT 'Foreign key linking to land.irrigation_zone. Business justification: Irrigation field operations (pivot runs, drip events) are executed against specific irrigation zones. Water use reporting, water right permit compliance, and irrigation scheduling all require linking ',
    `land_soil_sample_id` BIGINT COMMENT 'Foreign key linking to land.soil_sample. Business justification: Fertilizer and lime application operations are directly triggered by soil sample recommendations (nitrogen_recommendation_lbs_ac, lime_recommendation_lbs_ac). Nutrient management plans and 4R complian',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: Variable-rate field operations (seeding, fertilizer, chemical application) are planned and executed at management zone level. Zone-level input tracking and yield attribution reports require linking ea',
    `master_id` BIGINT COMMENT 'Reference to the seed, agrochemical, or fertilizer product applied during this operation. Nullable for non-application operations (e.g., tillage, scouting). Links to agrochemical_product or material_master for MRL compliance and FSMA traceability.',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: Field operations involving restricted-use pesticide application, irrigation from permitted water sources, or aerial application require an active permit. Linking field_operation to permit supports rea',
    `asset_id` BIGINT COMMENT 'Reference to the primary equipment asset (tractor, combine, sprayer, planter, irrigation system) used in this operation. Links to the equipment asset master for OEE tracking and CAPEX/OPEX cost allocation per ISO 55000.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Field operations consume procured inputs (seeds, chemicals, fertilizers). Linking field_operation to the sourcing purchase_order enables input traceability from procurement through field application —',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Harvest field operations fulfill specific forward sales contracts in grain farming. Contract fulfillment tracking requires linking each harvest run to the sales contract it delivers against, enabling ',
    `seed_variety_id` BIGINT COMMENT 'Foreign key linking to product.seed_variety. Business justification: Planting field operations must record the specific seed variety planted for variety performance analysis, yield attribution, and seed lot traceability. Agronomists and seed dealers require variety-lev',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Spray operations (herbicide, fungicide, insecticide) must be conducted within EPA/label-compliant spray windows. Linking field_operation to the authorizing spray_window is a core agrochemical regulato',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Research Field Operation Audit / GLP Compliance: field operations executed on trial plots must be traceable to the governing research trial to verify protocol adherence (correct equipment, timing, rat',
    `use_plan_id` BIGINT COMMENT 'Foreign key linking to land.land_use_plan. Business justification: Field operations are executed against an approved land use plan (planned commodity, tillage system, crop restrictions). Linking operations to the plan enables plan-vs-actual execution tracking, FSA co',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the VRA prescription file that governed application rates for this operation. Nullable for non-VRA operations. Supports as-applied vs. as-prescribed deviation analysis in Trimble Ag Software and Climate FieldView.',
    `water_right_id` BIGINT COMMENT 'Foreign key linking to land.water_right. Business justification: Irrigation field operations must be traceable to the authorizing water right permit for annual water use reporting, curtailment compliance, and state water agency audits. Regulators in prior-appropria',
    `observation_id` BIGINT COMMENT 'Reference to the weather observation record at the time of the operation. Used to validate spray window compliance (wind speed, temperature, humidity), PHI/REI conditions, and post-operation efficacy correlation.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to equipment.work_order. Business justification: field_operation currently stores work_order_number as a STRING reference but has no proper FK to work_order. Field operations (spraying, planting, harvesting) are often executed under a work order in ',
    `workforce_certification_id` BIGINT COMMENT 'Foreign key linking to workforce.workforce_certification. Business justification: EPA WPS and state pesticide laws require pesticide application field operations to be performed by a licensed applicator. Linking to the specific workforce_certification record enables automated licen',
    `application_rate` DECIMAL(18,2) COMMENT 'Actual quantity of product applied per unit area (e.g., oz/acre, lbs/acre, gallons/acre, seeds/acre). As-applied value from VRA controller or flow meter. Compared against VRA prescription for compliance and efficacy analysis.',
    `application_rate_uom` STRING COMMENT 'Unit of measure for the application_rate field. Ensures dimensional consistency across operations involving different product types (seeds, liquids, granulars). Required for MRL compliance calculations and FSMA records. [ENUM-REF-CANDIDATE: oz/acre|lbs/acre|gal/acre|seeds/acre|kg/ha|L/ha|mt/acre — 7 candidates stripped; promote to reference product]',
    `area_covered_acres` DECIMAL(18,2) COMMENT 'Total field area covered during the operation, measured in acres. Sourced from GPS track data (John Deere Operations Center / Trimble RTK). Used for application rate normalization, cost-per-acre analysis, and USDA FSA reporting.',
    `cost_center_code` STRING COMMENT 'SAP CO cost center to which the operational costs (fuel, labor, product) of this field operation are allocated. Enables OPEX tracking by farm unit, crop type, or management zone for financial reporting under GAAP/IFRS.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this field operation record was first created in the system, either via telematics auto-ingestion or manual entry. Used for data lineage, audit trail, and FSMA record-keeping compliance.',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the field operation was completed or stopped. Used with start_timestamp to compute operation duration, machine utilization, and OEE metrics.',
    `equipment_hours_used` DECIMAL(18,2) COMMENT 'Total machine hours logged by the primary asset during this operation, sourced from John Deere Operations Center engine hour meter. Used for preventive maintenance scheduling (PM triggers), OEE calculation, and CAPEX depreciation tracking.',
    `fuel_consumed_gal` DECIMAL(18,2) COMMENT 'Total fuel consumed by the equipment during the operation, in US gallons. Sourced from John Deere Operations Center telematics. Used for OPEX cost allocation, carbon footprint reporting (ISCC), and equipment efficiency benchmarking.',
    `gps_track_file_ref` STRING COMMENT 'File path or URI reference to the GPS/RTK track file recorded during the operation (Trimble .agdata, Climate FieldView .shp, or John Deere Operations Center export). Supports precision agriculture audit trails, pass efficiency calculation, and Esri ArcGIS spatial analysis.',
    `lot_number` STRING COMMENT 'Batch or lot number of the seed, chemical, or fertilizer product applied. Critical for FSMA forward/backward traceability, product recall management, and Certificate of Analysis (COA) linkage. Sourced from SAP MM goods issue records.',
    `ndvi_reference` DECIMAL(18,2) COMMENT 'NDVI value of the field at the time of operation, sourced from satellite or drone imagery (Esri ArcGIS / Climate FieldView). Used to correlate operation timing with crop health status and validate VRA prescription zones.',
    `operation_date` DATE COMMENT 'Calendar date on which the field operation was performed. Used for day-level scheduling, PHI/REI compliance countdown, weather correlation, and FSMA as-applied record dating.',
    `operation_notes` STRING COMMENT 'Free-text field for operator or agronomist observations recorded during or after the field operation (e.g., equipment issues, unusual field conditions, pest observations). Supports scouting follow-up and SOP deviation documentation.',
    `operation_number` STRING COMMENT 'Externally-known business identifier for the field operation, sourced from John Deere Operations Center or Trimble Ag Software. Used for cross-system traceability and FSMA audit trail references. Format: FOP-{YYYY}-{NNNNNN}.. Valid values are `^FOP-[0-9]{4}-[0-9]{6}$`',
    `operation_status` STRING COMMENT 'Current lifecycle state of the field operation. Drives operational dashboards, work order closure in SAP PM, and FSMA as-applied record completeness checks.. Valid values are `planned|in_progress|completed|cancelled|paused`',
    `operation_type` STRING COMMENT 'Classification of the agricultural field operation performed. Determines applicable compliance rules (e.g., PHI/REI for spraying, FSMA traceability for planting/harvesting) and links to relevant crop management records. [ENUM-REF-CANDIDATE: planting|spraying|tillage|harvesting|irrigation|fertilization|scouting|seeding|cultivation|cover_crop — promote to reference product]',
    `pass_efficiency_pct` DECIMAL(18,2) COMMENT 'Ratio of effective area covered to total area traversed, expressed as a percentage. Measures overlap and skip rates from GPS track analysis. Key precision agriculture KPI for equipment calibration and operator performance.',
    `phi_compliant` BOOLEAN COMMENT 'Indicates whether the required Pre-Harvest Interval was observed between the last chemical application and the scheduled harvest date. Critical for MRL compliance, FSMA food safety records, and GLOBALG.A.P. certification audits.',
    `rei_compliant` BOOLEAN COMMENT 'Indicates whether the Restricted Entry Interval was enforced after pesticide application, preventing unauthorized field re-entry. Required for OSHA worker protection standard compliance and EPA FIFRA label adherence.',
    `source_system` STRING COMMENT 'Originating operational system from which this field operation record was ingested into the Silver Layer. Supports data lineage, reconciliation, and audit trail requirements for FSMA and GLOBALG.A.P. record-keeping.. Valid values are `john_deere_ops_center|trimble_ag|climate_fieldview|granular|manual_entry`',
    `speed_avg_mph` DECIMAL(18,2) COMMENT 'Average ground speed of the equipment during the operation in miles per hour, derived from John Deere Operations Center telematics. Used to assess application uniformity, operator compliance with label speed requirements, and equipment performance benchmarking.',
    `spray_window_compliant` BOOLEAN COMMENT 'Indicates whether the operation was conducted within the approved spray window conditions (wind speed, temperature, inversion risk) as defined by EPA label requirements and IPM protocols. Populated for spraying operations; null for non-spray operations.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the field operation commenced, recorded from John Deere Operations Center telematics or operator log. Principal business event timestamp for operation duration calculation and FSMA traceability records.',
    `target_area_acres` DECIMAL(18,2) COMMENT 'Planned area to be covered as specified in the field operation work order or crop plan. Compared against area_covered_acres to compute pass efficiency and identify coverage gaps.',
    `total_product_uom` STRING COMMENT 'Unit of measure for total_product_used. Aligns with the product label unit and SAP MM material master UOM for inventory reconciliation and FSMA lot traceability. [ENUM-REF-CANDIDATE: oz|lbs|gal|seeds|kg|L|mt|bu — 8 candidates stripped; promote to reference product]',
    `total_product_used` DECIMAL(18,2) COMMENT 'Total quantity of product consumed during the operation (application_rate × area_covered_acres, adjusted for actual flow meter readings). Used for inventory depletion in SAP MM, cost accounting, and chemical usage reporting to EPA/state agencies.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this field operation record. Supports Silver Layer change tracking, data quality monitoring, and audit trail requirements for FSMA and GLOBALG.A.P. record integrity.',
    CONSTRAINT pk_equipment_field_operation PRIMARY KEY(`equipment_field_operation_id`)
) COMMENT 'Records of field-level equipment operations including planting, spraying, tillage, harvesting, and irrigation runs. Captures operation type, asset used, operator, field/parcel reference, start/end datetime, total area covered (acres), application rate (for VRA operations), product applied (seed/chemical/fertilizer), pass efficiency, GPS track file reference (Trimble/Climate FieldView), fuel consumed, and operation status. SSOT for as-applied and as-planted records supporting FSMA traceability and precision agriculture audit trails.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`precision_device` (
    `precision_device_id` BIGINT COMMENT 'Unique surrogate identifier for each precision agriculture hardware device record in the master registry. Primary key for the precision_device entity.',
    `asset_id` BIGINT COMMENT 'Reference to the parent equipment asset (tractor, combine, sprayer, planter, irrigation system, etc.) to which this precision device is attached or integrated. Supports asset-device association for telematics and precision agriculture hardware lifecycle management.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Precision devices are acquired via purchase orders. The precision_device has a denormalized po_number string. Linking to procurement.purchase_order enables full procurement-to-deployment traceability ',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Precision ag devices (GPS receivers, VRA controllers, section controllers) are procured from specific vendors. Linking precision_device to procurement.vendor enables vendor performance tracking for pr',
    `accuracy_class` STRING COMMENT 'Standardized accuracy classification tier for the precision device, enabling fleet-level reporting and field assignment decisions. Sub-inch RTK devices are required for high-precision VRA and planting operations.. Valid values are `sub_inch_rtk|inch_rtk|decimeter|meter|sub_percent|percent`',
    `accuracy_specification` STRING COMMENT 'Manufacturer-stated positional or measurement accuracy specification for the device (e.g., <2.5 cm RTK, <1 inch RTK sub-inch, ±0.5% flow rate). Critical for VRA prescription compliance, RTK guidance validation, and GLOBALG.A.P. precision agriculture certification.',
    `asset_tag_number` STRING COMMENT 'Internal fixed asset tag or barcode number affixed to the physical device for inventory control and asset audits. Corresponds to the asset tag in SAP S/4HANA Fixed Asset Accounting (FI-AA) and physical inventory records.',
    `calibration_interval_days` STRING COMMENT 'Number of days between required calibration events for this device, as specified by the OEM or internal calibration policy. Used to auto-calculate next_calibration_date and generate preventive maintenance schedules.',
    `calibration_status` STRING COMMENT 'Current calibration compliance status of the precision device. due_soon is triggered when next_calibration_date is within the lead-time threshold. overdue blocks device use in compliance-sensitive operations per GLOBALG.A.P. and FSMA requirements.. Valid values are `current|due_soon|overdue|not_required`',
    `calibration_technician` STRING COMMENT 'Name or identifier of the technician or certified service provider who performed the most recent calibration. Required for audit trail and GLOBALG.A.P. record-keeping compliance.',
    `communication_protocol` STRING COMMENT 'Primary data communication protocol used by the precision device to transmit data to the FMIS, telematics platform, or ISOBUS terminal. Determines integration architecture and data pipeline design. [ENUM-REF-CANDIDATE: ISOBUS|CAN_bus|NMEA_0183|NMEA_2000|RS232|Bluetooth|WiFi|cellular_4G|cellular_5G|LoRaWAN — promote to reference product]',
    `correction_source` STRING COMMENT 'Differential correction signal source used by GPS/RTK receivers to achieve sub-inch or sub-decimeter accuracy (e.g., RTK base station, WAAS, John Deere StarFire, Trimble CenterPoint RTX). Determines achievable accuracy class and subscription cost allocation. [ENUM-REF-CANDIDATE: RTK_base_station|SBAS|WAAS|OmniSTAR|StarFire|CenterPoint_RTX|none — 7 candidates stripped; promote to reference product]',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the precision device record was first created in the master registry. Provides audit trail for data governance and ISO 55000 asset lifecycle management compliance.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the purchase_cost and any financial values on this record (e.g., USD, EUR, CAD). Required for multi-currency CAPEX reporting.. Valid values are `^[A-Z]{3}$`',
    `data_output_format` STRING COMMENT 'Primary data output format generated by the precision device for integration with FMIS platforms, GIS systems, and agronomic analytics tools (e.g., ISOXML for ISOBUS-compliant devices, shapefile for GIS integration with Esri ArcGIS).. Valid values are `ISOXML|shapefile|GeoJSON|CSV|proprietary`',
    `decommission_date` DATE COMMENT 'Date the precision device was permanently removed from service and decommissioned. Marks the end of the devices operational lifecycle. Null for active devices. Required for asset lifecycle reporting and CAPEX write-off processing.',
    `device_name` STRING COMMENT 'Human-readable descriptive name assigned to the precision device for operational identification (e.g., RTK Receiver - Combine 4, NDVI Sensor - Field 12 Sprayer). Supports field crew identification and FMIS integration.',
    `device_serial_number` STRING COMMENT 'Manufacturer-assigned unique serial number for the precision device. Used for warranty tracking, calibration records, and hardware lifecycle management. Sourced from device nameplate or manufacturer documentation.',
    `device_status` STRING COMMENT 'Current operational lifecycle status of the precision device. Drives maintenance scheduling, calibration compliance alerts, and asset utilization reporting. calibration_due triggers workflow in CMMS/FMIS.. Valid values are `active|inactive|calibration_due|out_of_service|decommissioned|in_repair`',
    `device_type` STRING COMMENT 'Classification of the precision agriculture hardware device by functional category. Determines applicable calibration standards, accuracy specifications, and integration protocols. [ENUM-REF-CANDIDATE: gps_rtk_receiver|vra_controller|ndvi_sensor|yield_monitor|flow_meter|section_control_module|isobus_terminal|guidance_display|soil_ec_sensor|variable_rate_controller — promote to reference product]',
    `firmware_version` STRING COMMENT 'Current firmware version installed on the precision device (e.g., 3.12.1). Critical for compatibility validation with ISOBUS terminals, VRA controllers, and FMIS platforms. Tracked to ensure OEM-recommended firmware levels are maintained.. Valid values are `^[0-9]+.[0-9]+(.[0-9]+)?(.[0-9]+)?$`',
    `fmis_device_code` STRING COMMENT 'External device identifier assigned by the connected FMIS platform (e.g., John Deere Operations Center device ID, Climate FieldView device ID, Trimble Ag Software device ID). Used for cross-system data reconciliation and telematics data linkage.',
    `installation_date` DATE COMMENT 'Date the precision device was physically installed on or integrated with the parent equipment asset. Marks the start of the devices operational lifecycle on that asset. Used for warranty period calculation and CAPEX depreciation tracking.',
    `ip_rating` STRING COMMENT 'IEC 60529 Ingress Protection rating indicating the devices resistance to dust and water (e.g., IP67 for dust-tight and immersion-resistant). Critical for field deployment suitability assessment in agricultural environments.. Valid values are `^IP[0-9X][0-9X]$`',
    `isobus_certified` BOOLEAN COMMENT 'Indicates whether the precision device holds official ISOBUS (ISO 11783) certification, enabling plug-and-play interoperability with ISOBUS-compliant tractors and implements. Required for VRA controller and section control module compatibility validation.',
    `last_calibration_date` DATE COMMENT 'Date on which the most recent calibration of the precision device was performed. Used to calculate calibration compliance status and trigger next calibration scheduling. Mandatory for GLOBALG.A.P. and FSMA traceability compliance.',
    `manufacturer` STRING COMMENT 'Name of the original equipment manufacturer (OEM) of the precision device (e.g., Trimble, John Deere, Raven Industries, Ag Leader, Topcon). Used for warranty management, technical support escalation, and procurement analytics.',
    `model_number` STRING COMMENT 'Manufacturer-assigned model or part number for the precision device (e.g., Trimble NAV-900, Raven Viper 4+). Used for spare parts procurement, firmware compatibility checks, and OEM service bulletin tracking.',
    `next_calibration_date` DATE COMMENT 'Scheduled date by which the next calibration of the precision device must be completed to maintain compliance. Calculated from last_calibration_date plus calibration_interval_days. Drives CMMS preventive maintenance work order generation.',
    `notes` STRING COMMENT 'Free-text field for operational notes, known issues, configuration remarks, or special handling instructions related to the precision device. Used by field technicians and precision agriculture specialists for contextual documentation.',
    `operating_temp_max_c` DECIMAL(18,2) COMMENT 'Maximum ambient temperature in degrees Celsius at which the precision device is rated to operate reliably. Used for summer deployment planning and heat-stress operational risk assessment in field conditions.',
    `operating_temp_min_c` DECIMAL(18,2) COMMENT 'Minimum ambient temperature in degrees Celsius at which the precision device is rated to operate reliably. Used for seasonal deployment planning and cold-climate operational risk assessment.',
    `power_source` STRING COMMENT 'Primary power supply method for the precision device. Determines installation requirements, field operational constraints, and maintenance considerations for remote or battery-powered sensors.. Valid values are `vehicle_12v|vehicle_24v|battery|solar|external_ac|poe`',
    `purchase_cost` DECIMAL(18,2) COMMENT 'Original acquisition cost of the precision device in the operating currency. Used for CAPEX tracking, asset depreciation calculations, and ROI analysis of precision agriculture hardware investments.',
    `purchase_date` DATE COMMENT 'Date the precision device was purchased or procured. Used as the anchor date for warranty period calculation, CAPEX depreciation schedules, and asset lifecycle reporting.',
    `section_count` STRING COMMENT 'Number of independently controllable sections on a section control module or VRA controller (e.g., 12-section boom sprayer, 24-row planter). Determines granularity of variable rate application and overlap reduction capability.',
    `signal_frequency_mhz` DECIMAL(18,2) COMMENT 'Operating signal frequency in megahertz for GPS/RTK receivers and radio-based precision devices (e.g., 1575.42 MHz for GPS L1, 1227.60 MHz for GPS L2). Used for interference analysis and regulatory spectrum compliance with FCC/USDA requirements.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when the precision device record was most recently modified. Used for change data capture (CDC) in the Databricks Silver Layer pipeline and audit trail compliance.',
    `warranty_expiry_date` DATE COMMENT 'Date on which the manufacturer warranty for the precision device expires. Used to determine whether repair costs are covered under warranty or charged to OPEX. Triggers procurement alerts for extended warranty decisions.',
    CONSTRAINT pk_precision_device PRIMARY KEY(`precision_device_id`)
) COMMENT 'Master registry of precision agriculture hardware devices attached to or integrated with equipment assets. Includes GPS/RTK receivers, VRA controllers, NDVI sensors, yield monitors, flow meters, section control modules, and ISOBUS terminals. Captures device type, manufacturer, model, serial number, firmware version, calibration date, calibration status, accuracy specification (RTK sub-inch), communication protocol, parent asset assignment, and activation status. Supports precision agriculture hardware lifecycle management and calibration compliance.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`calibration_event` (
    `calibration_event_id` BIGINT COMMENT 'Unique system-generated identifier for each calibration event record. Primary key for the calibration_event data product within the equipment domain.',
    `asset_id` BIGINT COMMENT 'Reference to the parent agricultural equipment asset (tractor, combine, sprayer, planter, irrigation system) on which the calibrated device or sensor is installed.',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Precision device calibration events in agriculture are frequently performed by external certified calibration service vendors. Linking calibration_event to the service vendor enables vendor qualificat',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: Failed calibrations on CCP instruments (temperature sensors, flow meters, application rate controllers) must generate quality CAPAs under HACCP prerequisite programs. This direct link supports FSMA Pr',
    `employee_id` BIGINT COMMENT 'Reference to the workforce record of the technician or operator who performed the calibration activity.',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Precision devices (flow meters, weigh scales, moisture sensors) installed at supply facilities require periodic calibration. Linking calibration_event to supply.facility normalizes the plain-text loca',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field where the calibration was performed in-situ (applicable for field-based calibrations such as yield monitor calibration during harvest or GPS accuracy checks during planting).',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: GAP/GFSI auditors review calibration records for CCP instruments (flow meters, scales, temperature sensors) as audit evidence. Linking calibration events to the quality inspection that reviewed or tri',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: State and EPA regulations mandate calibration intervals for pesticide application equipment and precision devices. Calibration events fulfill specific compliance obligations. Linking enables regulator',
    `precision_device_id` BIGINT COMMENT 'Reference to the precision agriculture device or equipment sensor that was calibrated (e.g., GPS/RTK receiver, flow meter, yield monitor, sprayer nozzle controller).',
    `trial_id` BIGINT COMMENT 'Foreign key linking to research.trial. Business justification: Pre-Trial Calibration Compliance: GLP requires all measurement devices used in a trial to be calibrated before use. Linking calibration_event to the trial enables Pre-Trial Calibration Compliance re',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Precision device calibrations (GPS/RTK receivers, flow meters, section controllers) require recording ambient weather conditions per calibration standards. Temperature and humidity affect calibration ',
    `work_order_id` BIGINT COMMENT 'Reference to the maintenance work order under which this calibration event was executed, linking to the CMMS/PM schedule in SAP S/4HANA.',
    `adjustment_description` STRING COMMENT 'Narrative description of the specific adjustment performed on the device during calibration, including parameter changes, offset corrections, or hardware modifications applied.',
    `adjustment_made` BOOLEAN COMMENT 'Indicates whether a physical or software adjustment was applied to the device during the calibration event (True = adjustment made; False = no adjustment required, device was within tolerance).',
    `calibration_date` DATE COMMENT 'The actual calendar date on which the calibration activity was performed. This is the principal business event date for the calibration record.',
    `calibration_end_time` TIMESTAMP COMMENT 'Precise date and time when the calibration procedure was completed or terminated, enabling duration tracking and technician productivity analysis.',
    `calibration_interval_days` STRING COMMENT 'The prescribed number of days between calibration events for this device type, as defined by OEM specifications, regulatory requirements, or internal quality standards. Used to calculate next_calibration_due_date.',
    `calibration_method` STRING COMMENT 'The procedural approach used to perform the calibration, distinguishing between field-based tests, laboratory procedures, OEM manufacturer procedures, third-party certified calibration, or automated self-check routines.. Valid values are `field_test|laboratory|manufacturer_procedure|third_party|automated_self_check`',
    `calibration_standard` STRING COMMENT 'The reference standard, certified instrument, or traceable measurement benchmark used to perform the calibration (e.g., NIST-traceable reference, OEM factory standard, ISO 17025 accredited lab standard). Ensures traceability of measurement accuracy.',
    `calibration_start_time` TIMESTAMP COMMENT 'Precise date and time when the calibration procedure commenced, used for duration calculation and audit trail purposes.',
    `calibration_status` STRING COMMENT 'Current lifecycle state of the calibration event, tracking workflow from scheduling through completion or failure. [ENUM-REF-CANDIDATE: scheduled|in_progress|completed|failed|cancelled|overdue — promote to reference product if additional states are required]. Valid values are `scheduled|in_progress|completed|failed|cancelled|overdue`',
    `calibration_type` STRING COMMENT 'Classification of the calibration activity performed, identifying the specific precision agriculture device category being calibrated. Supports GPS/RTK accuracy checks, flow meter calibration, yield monitor calibration, sprayer nozzle checks, and soil sensor calibration. [ENUM-REF-CANDIDATE: gps_accuracy_check|flow_meter|yield_monitor|sprayer_nozzle|rtk_base_station|soil_sensor|ec_sensor|ph_sensor — promote to reference product]',
    `certificate_issued_date` DATE COMMENT 'The date on which the calibration certificate was formally issued, which may differ from the calibration date if certificate processing involves a review period.',
    `certificate_number` STRING COMMENT 'The reference number of the calibration certificate issued upon successful completion of the calibration event. Used for regulatory compliance documentation, audit trails, and GLOBALG.A.P. certification evidence.',
    `cmms_notification_number` STRING COMMENT 'The SAP PM notification number associated with this calibration event, providing traceability back to the CMMS system of record for maintenance history and cost allocation.',
    `cost_center_code` STRING COMMENT 'The SAP CO cost center code to which the labor and material costs of this calibration event are allocated, supporting OPEX tracking and equipment lifecycle cost management.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when this calibration event record was first created in the system, providing the audit trail creation marker for data lineage and compliance purposes.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to labor_cost and parts_cost fields (e.g., USD, EUR, BRL). Supports multi-currency operations for global agricultural enterprises.. Valid values are `^[A-Z]{3}$`',
    `deviation_value` DECIMAL(18,2) COMMENT 'The calculated absolute difference between the post-calibration reading and the reference standard reading, indicating residual measurement error after calibration adjustment.',
    `device_serial_number` STRING COMMENT 'Manufacturer-assigned serial number of the precision agriculture device or sensor being calibrated, used for asset tracking, warranty management, and OEM service records.',
    `device_type` STRING COMMENT 'Category of the precision agriculture device or sensor being calibrated, providing classification context for analytics and maintenance planning. [ENUM-REF-CANDIDATE: gps_receiver|rtk_receiver|flow_meter|yield_monitor|sprayer_controller|soil_sensor|weather_sensor|vra_controller|nozzle_assembly — promote to reference product]',
    `event_number` STRING COMMENT 'Externally visible, human-readable business identifier for the calibration event, used in certificates, audit trails, and regulatory submissions. Format: CAL-YYYY-NNNNNN.. Valid values are `^CAL-[0-9]{4}-[0-9]{6}$`',
    `labor_cost` DECIMAL(18,2) COMMENT 'The actual labor cost incurred for performing the calibration event, expressed in the operational currency. Contributes to OPEX tracking and equipment total cost of ownership analysis.',
    `location_description` STRING COMMENT 'Description of the physical location where the calibration was performed (e.g., field workshop, equipment yard, certified calibration lab, in-field during operation). Supports audit trail and logistics planning.',
    `measurement_unit` STRING COMMENT 'Unit of measure applicable to the pre-calibration, post-calibration, and reference standard readings (e.g., gal/min for flow meters, bu/ac for yield monitors, meters for GPS accuracy, mS/cm for EC sensors, pH units).',
    `next_calibration_due_date` DATE COMMENT 'The scheduled date by which the next calibration of this device must be completed to maintain measurement accuracy compliance. Drives preventive maintenance scheduling and CMMS work order generation.',
    `notes` STRING COMMENT 'Free-text field for technician observations, environmental conditions during calibration, anomalies encountered, or additional context not captured in structured fields. Supports root cause analysis and audit review.',
    `parts_cost` DECIMAL(18,2) COMMENT 'The actual cost of any replacement parts or consumables used during the calibration event, expressed in the operational currency. Contributes to OPEX and parts inventory cost tracking.',
    `pass_fail_result` STRING COMMENT 'The outcome determination of the calibration event: pass (within tolerance), fail (outside tolerance), or conditional_pass (within tolerance with noted conditions). Drives device release for field operations or quarantine for repair.. Valid values are `pass|fail|conditional_pass`',
    `post_calibration_reading` DECIMAL(18,2) COMMENT 'The measured value recorded from the device or sensor immediately after the calibration adjustment was applied. Compared against the reference standard to confirm calibration success.',
    `pre_calibration_reading` DECIMAL(18,2) COMMENT 'The measured value recorded from the device or sensor immediately before the calibration adjustment was applied. Used to quantify measurement drift and justify calibration necessity.',
    `reference_standard_reading` DECIMAL(18,2) COMMENT 'The known, certified value from the calibration reference standard against which pre- and post-calibration readings are compared. Establishes the target accuracy benchmark.',
    `regulatory_compliance_flag` BOOLEAN COMMENT 'Indicates whether this calibration event was performed to satisfy a specific regulatory or certification requirement (True = regulatory-driven calibration; False = routine preventive calibration). Supports FSMA, EPA, and GLOBALG.A.P. compliance reporting.',
    `regulatory_requirement_reference` STRING COMMENT 'Specific regulatory citation, certification standard, or compliance framework requirement that mandated this calibration event (e.g., FSMA Produce Safety Rule Section 112.50, GLOBALG.A.P. AF 7.1, EPA 40 CFR Part 170 REI compliance).',
    `tolerance_value` DECIMAL(18,2) COMMENT 'The maximum allowable deviation between the device reading and the reference standard for the calibration to be considered passing. Defines the acceptable accuracy threshold for the device type.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when this calibration event record was last modified, supporting audit trail requirements and data lineage tracking in the Databricks Silver Layer.',
    `vra_prescription_impact` BOOLEAN COMMENT 'Indicates whether the calibration result affects active Variable Rate Application (VRA) prescriptions. When True, downstream VRA prescription records must be reviewed for accuracy impact before field application.',
    CONSTRAINT pk_calibration_event PRIMARY KEY(`calibration_event_id`)
) COMMENT 'Records of calibration activities performed on precision agriculture devices and equipment sensors. Captures calibration date, device/sensor calibrated, calibration type (GPS accuracy check, flow meter calibration, yield monitor calibration, sprayer nozzle check), technician performing calibration, calibration standard used, pre-calibration reading, post-calibration reading, pass/fail result, next calibration due date, and certificate reference. Ensures measurement accuracy for VRA prescriptions, yield data integrity, and regulatory compliance.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset_inspection` (
    `asset_inspection_id` BIGINT COMMENT 'Unique system-generated identifier for each asset inspection record. Primary key for the asset_inspection data product within the equipment domain.',
    `asset_id` BIGINT COMMENT 'Reference to the agricultural equipment asset (tractor, combine, planter, sprayer, irrigation system, etc.) that was inspected. Links to the equipment asset master record.',
    `inspection_checklist_template_id` BIGINT COMMENT 'Reference to the standardized inspection checklist template used for this inspection. Templates are defined per inspection type and asset category, ensuring consistent evaluation criteria across all inspections of the same type.',
    `corrective_action_id` BIGINT COMMENT 'Foreign key linking to quality.corrective_action. Business justification: Equipment inspections finding deficiencies on food-contact or CCP equipment generate quality CAPAs under FSMA prerequisite programs. Linking asset_inspection to the resulting corrective_action support',
    `employee_id` BIGINT COMMENT 'Reference to the workforce record of the individual who conducted the inspection. May be an internal technician, certified safety officer, or third-party inspector.',
    `field_id` BIGINT COMMENT 'Foreign key linking to land.field. Business justification: Pesticide applicator equipment inspections and sprayer calibration checks are conducted in-field per EPA and state regulatory requirements. Recording which field the inspection occurred in supports co',
    `inspection_record_id` BIGINT COMMENT 'Foreign key linking to compliance.inspection_record. Business justification: Regulatory agency inspections of agricultural equipment (DOT, OSHA, EPA spray equipment audits) generate both an equipment-side asset_inspection and a compliance-side inspection_record. Linking them e',
    `maintenance_plan_id` BIGINT COMMENT 'Foreign key linking to equipment.maintenance_plan. Business justification: Scheduled asset inspections in agricultural equipment management are typically triggered by preventive maintenance plans (e.g., a 500-hour PM plan includes a safety inspection checklist). asset_inspec',
    `obligation_id` BIGINT COMMENT 'Foreign key linking to compliance.compliance_obligation. Business justification: DOT annual vehicle inspections, OSHA equipment safety checks, and EPA spray equipment calibrations are compliance obligations fulfilled by asset inspections. Linking asset_inspection to compliance_obl',
    `work_order_id` BIGINT COMMENT 'Reference to the maintenance work order associated with this inspection, if the inspection was triggered by or resulted in a corrective or preventive maintenance work order in the CMMS.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Field asset inspections (sprayer calibration checks, structural post-storm inspections) require documenting ambient weather conditions at time of inspection for regulatory validity. Calibration and in',
    `asset_grounded_flag` BOOLEAN COMMENT 'Indicates whether the asset has been taken out of service (grounded) as a result of this inspection. A True value means the asset must not be operated until corrective actions are completed and a re-inspection passes.',
    `asset_hours_at_inspection` DECIMAL(18,2) COMMENT 'The cumulative engine or operating hours recorded on the asset at the time of inspection, as read from the telematics system (John Deere Operations Center) or hour meter. Critical for hour-based maintenance interval tracking per ISO 55000 and OEM service schedules.',
    `certificate_expiry_date` DATE COMMENT 'The date on which the regulatory compliance certificate issued as a result of this inspection expires. Drives the scheduling of the next mandatory inspection to maintain continuous compliance.',
    `certificate_number` STRING COMMENT 'The official certificate or compliance document number issued by the regulatory authority or internal compliance function upon successful inspection. Used for regulatory audit trails and insurance documentation.',
    `checklist_item_count` STRING COMMENT 'Total number of individual checklist items evaluated during the inspection. Provides a completeness indicator and supports audit verification that all required inspection points were assessed.',
    `corrective_action_description` STRING COMMENT 'Detailed description of the corrective actions required or taken to address deficiencies identified during the inspection. May reference specific repair procedures, parts replacement, or regulatory remediation steps.',
    `corrective_action_required` BOOLEAN COMMENT 'Indicates whether corrective actions are mandated as a result of this inspection. True triggers the creation of a corrective maintenance work order or formal corrective action plan in the CMMS.',
    `created_timestamp` TIMESTAMP COMMENT 'The date and time when the inspection record was first created in the system. Provides the audit trail creation marker for data lineage and compliance purposes.',
    `critical_deficiency_flag` BOOLEAN COMMENT 'Indicates whether one or more critical safety or regulatory deficiencies were identified during the inspection. A True value typically triggers immediate asset grounding, mandatory corrective action, and escalation to the safety or compliance officer.',
    `deficiency_description` STRING COMMENT 'Narrative description of all deficiencies, non-conformances, or safety hazards identified during the inspection. Captures the nature, location, and severity of each issue found. Used for corrective action planning and regulatory reporting.',
    `dot_compliance_verified` BOOLEAN COMMENT 'Indicates whether DOT roadworthiness and transport safety requirements were specifically verified as part of this inspection, applicable to road-mobile agricultural equipment and transport vehicles.',
    `epa_compliance_verified` BOOLEAN COMMENT 'Indicates whether EPA environmental compliance requirements (e.g., engine emissions, fuel system integrity, chemical containment) were specifically verified as part of this inspection.',
    `inspection_date` DATE COMMENT 'The actual calendar date on which the inspection was conducted. This is the principal real-world business event date for the inspection record and is used for regulatory compliance tracking and certificate validity calculations.',
    `inspection_end_timestamp` TIMESTAMP COMMENT 'The precise date and time when the inspector completed all checklist evaluations and closed the inspection. Used for duration calculation and audit trail purposes.',
    `inspection_location` STRING COMMENT 'The physical location or functional location code where the inspection was conducted, such as a farm field identifier, workshop bay, or GPS-referenced field location. Aligns with SAP PM functional location hierarchy and Esri ArcGIS field mapping.',
    `inspection_method` STRING COMMENT 'The primary method used to conduct the inspection. Visual inspections rely on direct observation; operational tests involve running the equipment through functional checks; instrument measurement uses calibrated tools (e.g., emissions analyser, torque wrench); document review verifies maintenance records and certifications; combined uses multiple methods.. Valid values are `visual|operational_test|instrument_measurement|document_review|combined`',
    `inspection_notes` STRING COMMENT 'Free-text field for the inspector to record additional observations, contextual information, or recommendations that do not fit within the structured checklist items. Supports comprehensive documentation for audit and insurance purposes.',
    `inspection_number` STRING COMMENT 'Externally-known, human-readable business identifier for the inspection record, used in regulatory submissions, insurance documentation, and CMMS cross-referencing. Typically generated by SAP QM or the CMMS system.. Valid values are `^INSP-[0-9]{4}-[0-9]{6}$`',
    `inspection_start_timestamp` TIMESTAMP COMMENT 'The precise date and time when the inspector began conducting the inspection. Used for duration calculation and audit trail purposes.',
    `inspection_status` STRING COMMENT 'Current lifecycle state of the inspection record. Scheduled indicates the inspection is planned but not yet started; in_progress indicates the inspector is actively conducting the inspection; completed indicates all checklist items have been evaluated and the record is closed; cancelled indicates the inspection was voided; pending_reinspection indicates deficiencies were found requiring a follow-up inspection.. Valid values are `scheduled|in_progress|completed|cancelled|pending_reinspection`',
    `inspection_type` STRING COMMENT 'Classification of the inspection by its regulatory or operational purpose. Pre-season inspections verify readiness before planting or harvest campaigns; OSHA safety inspections verify compliance with occupational safety standards; EPA emissions inspections verify engine and exhaust compliance; DOT roadworthiness inspections verify road-legal status for transport; insurance inspections support coverage underwriting; post-repair inspections verify corrective action effectiveness; ad-hoc inspections are unscheduled. [ENUM-REF-CANDIDATE: pre_season|osha_safety|epa_emissions|dot_roadworthiness|insurance|post_repair|ad_hoc — promote to reference product]',
    `inspector_certification_number` STRING COMMENT 'The professional certification or licence number of the inspector who conducted the inspection, as issued by the relevant regulatory or professional body. Required for regulatory audit trails to verify inspector qualification.',
    `inspector_type` STRING COMMENT 'Classification of the inspector who conducted the inspection. Internal indicates a company-employed technician or safety officer; third_party indicates an independent certified inspector engaged by the company; regulatory_authority indicates an inspector from a government body such as OSHA, EPA, or DOT.. Valid values are `internal|third_party|regulatory_authority`',
    `items_failed_count` STRING COMMENT 'Number of individual checklist items that received a fail evaluation during the inspection. A non-zero value triggers deficiency documentation and corrective action requirements.',
    `items_passed_count` STRING COMMENT 'Number of individual checklist items that received a pass evaluation during the inspection. Used in conjunction with checklist_item_count and items_failed_count to assess inspection completeness and asset condition.',
    `next_scheduled_inspection_date` DATE COMMENT 'The calculated or manually assigned date for the next scheduled inspection of this asset, based on regulatory intervals, OEM recommendations, or the preventive maintenance plan. Drives the forward maintenance calendar.',
    `osha_compliance_verified` BOOLEAN COMMENT 'Indicates whether OSHA occupational safety requirements were specifically verified as part of this inspection. Supports OSHA compliance reporting and audit readiness under 29 CFR 1910 and 29 CFR 1928 (agricultural operations).',
    `overall_result` STRING COMMENT 'The aggregate pass/fail determination for the entire inspection. Pass indicates all checklist items met required standards; fail indicates one or more critical items did not meet standards; conditional_pass indicates minor deficiencies noted but asset is operationally cleared with corrective actions required; incomplete indicates the inspection was not fully executed.. Valid values are `pass|fail|conditional_pass|incomplete`',
    `regulatory_certificate_issued` BOOLEAN COMMENT 'Indicates whether a regulatory compliance certificate (e.g., OSHA safety certificate, DOT roadworthiness certificate, EPA emissions certificate) was issued as a result of this inspection passing.',
    `reinspection_due_date` DATE COMMENT 'The date by which a follow-up re-inspection must be completed to verify that corrective actions have been implemented and deficiencies resolved. Mandatory when overall_result is fail or conditional_pass.',
    `scheduled_date` DATE COMMENT 'The planned calendar date on which the inspection was scheduled to occur, as defined in the preventive maintenance plan or regulatory compliance calendar.',
    `updated_timestamp` TIMESTAMP COMMENT 'The date and time when the inspection record was most recently modified. Supports data lineage tracking, audit trails, and incremental data pipeline processing in the Databricks Lakehouse Silver Layer.',
    CONSTRAINT pk_asset_inspection PRIMARY KEY(`asset_inspection_id`)
) COMMENT 'Scheduled and ad-hoc inspection records for agricultural equipment assets covering safety, regulatory, and operational readiness checks. Captures inspection type (pre-season, OSHA safety, EPA emissions, DOT roadworthiness, insurance), inspection date, inspector identity, asset inspected, checklist items evaluated, pass/fail per item, overall inspection result, deficiencies noted, corrective actions required, re-inspection due date, and regulatory certificate issued. Supports OSHA compliance, insurance requirements, and ISO 55000 asset condition monitoring.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset_assignment` (
    `asset_assignment_id` BIGINT COMMENT 'Unique surrogate identifier for each equipment asset assignment record in the Silver Layer lakehouse. Primary key for the asset_assignment data product.',
    `asset_id` BIGINT COMMENT 'Reference to the specific agricultural equipment or fleet asset being assigned (e.g., tractor, combine, planter, sprayer, irrigation system). Links to the equipment master record.',
    `cost_center_id` BIGINT COMMENT 'Reference to the SAP CO cost center to which CAPEX/OPEX costs for this equipment assignment are allocated. Enables cost allocation by crop enterprise or farm unit.',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Assets (combines, sprayers) are assigned to entire crews for seasonal operations in agriculture. Crew-level asset assignment drives seasonal utilization planning, crew productivity reporting, and cust',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Reference to the crop enterprise (e.g., corn, soybean, wheat production unit) to which the equipment assignment is attributed for cost allocation and operational planning purposes.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Custom hire service management: asset assignments for custom hire operations must reference the customer account for service scheduling, billing, and performance reporting. custom_hire_customer_ref ',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Asset assignments cover deployment of equipment to supply facilities (e.g., a forklift assigned to a grain elevator during harvest season). This link enables facility managers to track which assets ar',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm unit or farm location to which the equipment asset is assigned. Supports multi-location fleet scheduling and CAPEX/OPEX allocation by farm operation.',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: Equipment assignments are made against specific field crop plans — a planter is assigned to execute a specific crop plan for a field/season. Linking enables planned vs. actual equipment utilization re',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field or land parcel to which the equipment asset is assigned. Applicable when the assigned-to entity type is a field. Supports GIS-based field mapping via Esri ArcGIS.',
    `employee_id` BIGINT COMMENT 'Reference to the primary operator (employee or contractor) responsible for operating the assigned equipment asset during the assignment period. Sourced from SAP SuccessFactors workforce records.',
    `precision_device_id` BIGINT COMMENT 'The identifier of the RTK GPS receiver unit installed on the equipment asset during this assignment. Enables sub-inch positioning accuracy for precision planting, VRA, and field mapping operations.',
    `actual_area_hectares` DECIMAL(18,2) COMMENT 'The actual land area in hectares covered by the equipment asset during the assignment period, sourced from GPS/RTK telematics data in John Deere Operations Center or Trimble Ag Software.',
    `actual_return_date` DATE COMMENT 'The actual calendar date on which the equipment asset was physically returned or released from the assignment. May differ from the planned end_date due to operational delays or early completion.',
    `actual_utilization_hours` DECIMAL(18,2) COMMENT 'The actual number of engine/operational hours the equipment asset accumulated during the assignment period, sourced from John Deere Operations Center telematics. Used for OEE calculation and OPEX cost allocation.',
    `assigned_to_entity_type` STRING COMMENT 'Discriminator indicating the type of business entity to which the equipment asset is assigned. Determines which reference ID (field_id, farm_unit_id, operator_id, crop_enterprise_id) is the primary assignment target.. Valid values are `field|farm_unit|operator|crop_enterprise|custom_hire`',
    `assignment_notes` STRING COMMENT 'Free-text field for operational notes, special instructions, or contextual information related to the equipment assignment (e.g., specific field conditions, equipment configuration requirements, custom hire terms).',
    `assignment_number` STRING COMMENT 'Externally-known business identifier for the equipment assignment record, following the format ASGN-YYYY-NNNNNN. Used for cross-referencing with John Deere Operations Center, SAP PM, and Granular Farm Management systems.. Valid values are `^ASGN-[0-9]{4}-[0-9]{6}$`',
    `assignment_purpose` STRING COMMENT 'The operational purpose or activity for which the equipment asset is assigned. Supports fleet scheduling, utilization analysis, and OPEX allocation by agricultural activity. [ENUM-REF-CANDIDATE: planting|tillage|spraying|harvesting|irrigation|transport|custom_hire|maintenance_support|other — promote to reference product]',
    `assignment_status` STRING COMMENT 'Current lifecycle status of the equipment asset assignment. planned indicates a future assignment; active indicates the asset is currently deployed; suspended indicates a temporary pause; completed indicates the assignment period has ended; cancelled indicates the assignment was voided.. Valid values are `planned|active|suspended|completed|cancelled`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the asset assignment record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Provides audit trail for record provenance and data lineage in the Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to the hourly rate and cost values for this assignment (e.g., USD, EUR, BRL). Supports multi-currency operations for international farm operations.. Valid values are `^[A-Z]{3}$`',
    `custom_hire_flag` BOOLEAN COMMENT 'Indicates whether this equipment assignment is a custom hire arrangement (True) where the equipment is operated for a third-party customer or contracted service, or an internal farm operation (False). Affects billing and revenue recognition.',
    `end_date` DATE COMMENT 'The calendar date on which the equipment asset assignment is scheduled to end or was actually completed. Null for open-ended assignments. Used for fleet availability planning.',
    `functional_location_code` STRING COMMENT 'The SAP PM functional location code representing the physical or logical location where the equipment asset is deployed during the assignment (e.g., farm site, field block, irrigation zone). Supports maintenance planning and asset hierarchy.',
    `gap_compliance_flag` BOOLEAN COMMENT 'Indicates whether this equipment assignment is conducted in compliance with Good Agricultural Practices (GAP) standards, including equipment calibration, chemical application records, and operator hygiene requirements.',
    `growing_season_code` STRING COMMENT 'The agricultural growing season identifier associated with this assignment (e.g., 2024-spring, 2024-fall). Enables seasonal fleet utilization analysis and crop enterprise cost allocation aligned with FMIS planning cycles.. Valid values are `^[0-9]{4}-(spring|summer|fall|winter|annual)$`',
    `hourly_rate` DECIMAL(18,2) COMMENT 'The internal charge-out or cost allocation rate per operational hour for the equipment asset during this assignment. Used for OPEX cost allocation to crop enterprises and custom hire billing.',
    `maintenance_plant_code` STRING COMMENT 'The SAP PM maintenance plant code identifying the organizational unit responsible for maintaining the equipment asset during this assignment period. Used for PM work order routing and spare parts procurement.',
    `operator_license_verified` BOOLEAN COMMENT 'Indicates whether the primary operators equipment operating license and certifications have been verified as current and valid for the assigned equipment type prior to assignment activation. Supports OSHA compliance.',
    `planned_area_hectares` DECIMAL(18,2) COMMENT 'The planned land area in hectares that the equipment asset is expected to cover during the assignment (e.g., acres to be planted, sprayed, or harvested). Supports YPM and operational efficiency analysis.',
    `planned_utilization_hours` DECIMAL(18,2) COMMENT 'The planned or budgeted number of engine/operational hours the equipment asset is expected to accumulate during the assignment period. Used for CAPEX/OPEX cost allocation and fleet scheduling.',
    `precision_ag_hardware_flag` BOOLEAN COMMENT 'Indicates whether the assigned equipment asset is equipped with precision agriculture hardware (True), such as GPS/RTK receivers, VRA controllers, or NDVI sensors, relevant for variable rate application prescriptions.',
    `safety_induction_completed` BOOLEAN COMMENT 'Indicates whether the assigned operator has completed the required safety induction and equipment-specific SOP training prior to commencing the assignment. Required for OSHA and GLOBALG.A.P. compliance.',
    `start_date` DATE COMMENT 'The calendar date on which the equipment asset assignment becomes effective and the asset is deployed to the assigned entity. Used for fleet scheduling and seasonal planning.',
    `total_assignment_cost` DECIMAL(18,2) COMMENT 'The total OPEX cost incurred for this equipment assignment, calculated as actual utilization hours multiplied by the hourly rate plus any additional direct costs. Used for crop enterprise cost allocation and EBITDA reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the asset assignment record was last modified, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking, audit compliance, and incremental data loading in the Databricks Silver Layer.',
    `wbs_element` STRING COMMENT 'The SAP PS Work Breakdown Structure element code associated with this assignment for project-based CAPEX cost tracking (e.g., equipment deployment for a new irrigation project or precision ag hardware rollout).',
    CONSTRAINT pk_asset_assignment PRIMARY KEY(`asset_assignment_id`)
) COMMENT 'Records of equipment asset assignments to farm operations, fields, operators, and cost centers over time. Captures asset reference, assigned-to entity type (field, farm unit, operator, crop enterprise), assignment start date, assignment end date, primary operator, backup operator, assigned cost center (SAP CO), assignment purpose (planting season, harvest, custom hire), and utilization hours during assignment period. Enables CAPEX/OPEX cost allocation by crop enterprise and supports fleet scheduling across multiple farm locations.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`rental_lease` (
    `rental_lease_id` BIGINT COMMENT 'Unique surrogate identifier for each rental, lease, or custom hire agreement record in the equipment domain. Primary key for the rental_lease data product.',
    `invoice_id` BIGINT COMMENT 'Foreign key linking to invoice.invoice. Business justification: Equipment rental/custom hire agreements generate AR invoices billed to the hiring customer. Agriculture operations routinely invoice neighbors for custom hire equipment use. This link supports AR bill',
    `asset_id` BIGINT COMMENT 'Reference to the specific equipment asset record (tractor, combine, planter, sprayer, irrigation system, etc.) covered by this agreement. May be null for custom hire inbound where the counterparty supplies the asset.',
    `billing_schedule_id` BIGINT COMMENT 'Foreign key linking to invoice.billing_schedule. Business justification: Equipment rental and lease agreements with periodic payment structures (monthly, seasonal) are governed by billing schedules. Agriculture lease agreements for land-use equipment require automated recu',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Custom hire service billing: when a farm provides equipment hire services to neighboring operations or agribusiness customers, the rental_lease counterparty must be linked to a customer account for in',
    `facility_id` BIGINT COMMENT 'Foreign key linking to supply.facility. Business justification: Equipment rental and lease agreements for grain handling or processing equipment specify the supply facility where the equipment is deployed or must be returned. This link supports contract management',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field or land parcel associated with this agreement. Applicable when the lease or custom hire is tied to a defined field boundary. Links to the land and soil domain field master.',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Equipment rental and custom hire agreements generate recurring expense postings to GL accounts (operating lease expense, custom hire/contract services). Agriculture operations heavily use custom hire ',
    `vendor_id` BIGINT COMMENT 'Reference to the external party involved in the agreement — the lessor/rental provider for inbound agreements, or the lessee/customer for outbound agreements. Links to the vendor or customer master record.',
    `acreage_cap` DECIMAL(18,2) COMMENT 'Maximum contracted acreage covered under the agreement before excess-use charges apply. Applicable to per-acre custom hire and seasonal lease agreements. Supports fleet cost optimization and field coverage planning.',
    `agreement_number` STRING COMMENT 'Externally-known alphanumeric identifier assigned to the rental, lease, or custom hire agreement, used for cross-referencing with counterparty documents, SAP FI lease accounting, and IFRS 16 disclosures.',
    `agreement_status` STRING COMMENT 'Current lifecycle state of the rental or lease agreement. Draft indicates pending execution; active indicates in-force; suspended indicates temporarily paused; terminated indicates early exit; expired indicates natural end-of-term; closed indicates fully settled and archived.. Valid values are `draft|active|suspended|terminated|expired|closed`',
    `agreement_type` STRING COMMENT 'Classification of the equipment agreement: operating_lease (off-balance-sheet lease per IFRS 16 short-term exemption), finance_lease (on-balance-sheet right-of-use asset), rental (short-term ad hoc hire), custom_hire_inbound (external operator performs field operations for the enterprise), or custom_hire_outbound (enterprise provides equipment/operators to a third party). Drives CAPEX/OPEX treatment and revenue recognition.. Valid values are `operating_lease|finance_lease|rental|custom_hire_inbound|custom_hire_outbound`',
    `cost_center_code` STRING COMMENT 'SAP CO cost center to which the rental or lease expense (OPEX) or right-of-use asset depreciation (CAPEX) is allocated. Supports management accounting and EBITDA reporting by operational unit.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when this rental_lease record was first created in the system. Used for audit trail, data lineage, and SOX compliance.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code for all monetary values in this agreement (rate_amount, total_agreement_value, security_deposit_amount). Supports multi-currency operations for international agricultural enterprises.. Valid values are `^[A-Z]{3}$`',
    `custom_hire_service_type` STRING COMMENT 'For custom hire agreements (inbound or outbound), specifies the field operation service being contracted: planting, spraying, harvesting, hauling, tillage, or fertilizing. Set to not_applicable for pure equipment leases and rentals. [ENUM-REF-CANDIDATE: planting|spraying|harvesting|hauling|tillage|fertilizing|not_applicable — 7 candidates stripped; promote to reference product]',
    `early_termination_penalty` DECIMAL(18,2) COMMENT 'Contractual penalty amount payable if the agreement is terminated before the end_date. Used for lease exit cost analysis and IFRS 16 lease modification accounting. Null if no early termination clause exists.',
    `end_date` DATE COMMENT 'The contractual end date of the rental, lease, or custom hire agreement. For open-ended agreements this may be null. Used for lease term calculation, renewal planning, and IFRS 16 lease liability amortization schedule.',
    `equipment_category` STRING COMMENT 'Categorical classification of the equipment type covered by the agreement. Supports fleet cost optimization analysis and CAPEX/OPEX planning by equipment class. [ENUM-REF-CANDIDATE: tractor|combine|planter|sprayer|irrigation_system|hauling_vehicle|tillage|grain_cart|header|other — promote to reference product]',
    `equipment_description` STRING COMMENT 'Free-text description of the agricultural machinery or equipment covered by the agreement (e.g., John Deere 8R 410 Tractor, 60-ft Case IH 4440 Sprayer). Used when the asset is not registered in the internal asset master or for custom hire where the counterparty supplies equipment.',
    `execution_date` DATE COMMENT 'The date on which the agreement was formally signed and executed by both parties. May differ from the start_date (effective date). Used as the principal business event date for audit and legal reference.',
    `hours_cap` STRING COMMENT 'Maximum contracted engine or operational hours allowed under the agreement before excess-use charges apply. Applicable to hourly-rate rentals and operating leases. Sourced from John Deere Operations Center telematics for monitoring.',
    `insurance_policy_number` STRING COMMENT 'Reference number of the insurance policy covering the equipment under this agreement. Used for claims processing and compliance verification with contractual insurance requirements.',
    `insurance_required` BOOLEAN COMMENT 'Indicates whether the agreement contractually requires the enterprise or counterparty to maintain equipment insurance coverage. True if insurance is a contractual obligation.',
    `invoice_reference` STRING COMMENT 'Reference number of the most recent invoice issued or received under this agreement. Used for accounts payable/receivable matching in SAP FI and payment reconciliation.',
    `notes` STRING COMMENT 'Free-text field for additional contractual terms, special conditions, operational instructions, or compliance notes not captured in structured fields (e.g., GPS/RTK equipment requirements, VRA controller compatibility, PHI/REI obligations for custom hire spraying).',
    `payment_frequency` STRING COMMENT 'The schedule at which lease or rental payments are due: monthly, quarterly, seasonal (aligned to crop season), annual, per_use (invoiced per event), or upfront (single prepayment). Drives accounts payable scheduling in SAP FI.. Valid values are `monthly|quarterly|seasonal|annual|per_use|upfront`',
    `performance_metric_type` STRING COMMENT 'The type of quality or performance metric tracked under this agreement. For custom hire, this may be acres_completed, hours_logged, yield_achieved, or application_rate. Supports service-level verification and payment milestone validation.. Valid values are `acres_completed|hours_logged|yield_achieved|application_rate|not_tracked`',
    `performance_metric_value` DECIMAL(18,2) COMMENT 'The actual recorded value for the performance_metric_type tracked under this agreement (e.g., 450.5 acres completed, 320 hours logged). Used for milestone billing, service verification, and OEE benchmarking.',
    `purchase_option` BOOLEAN COMMENT 'Indicates whether the agreement includes an option for the enterprise to purchase the equipment at or before the end_date. True if a purchase option exists. A reasonably certain purchase option affects IFRS 16 finance lease classification.',
    `purchase_option_price` DECIMAL(18,2) COMMENT 'The contractual price at which the enterprise may purchase the leased equipment if the purchase_option is true. Used for lease vs. buy analysis and IFRS 16 lease classification assessment.',
    `rate_amount` DECIMAL(18,2) COMMENT 'The contracted rate per unit as defined by rate_structure (e.g., dollars per acre, dollars per hour, monthly payment amount). Used for invoice validation and cost benchmarking against owned-equipment OPEX.',
    `rate_structure` STRING COMMENT 'The billing rate basis for the agreement: per_acre (common for custom hire spraying/planting), per_hour (equipment rental), monthly (operating lease), seasonal (crop-season lease), annual (finance lease), or per_day (short-term rental). Drives invoice calculation and cost allocation.. Valid values are `per_acre|per_hour|monthly|seasonal|annual|per_day`',
    `renewal_option` BOOLEAN COMMENT 'Indicates whether the agreement includes a contractual option to renew at or before the end_date. True if a renewal option exists. Relevant for IFRS 16 lease term assessment and fleet planning.',
    `return_condition_terms` STRING COMMENT 'Free-text description of the contractual conditions under which the equipment must be returned at agreement end (e.g., normal wear and tear acceptable, full service required, maximum 2000 hours). Used for asset return inspection and dispute resolution.',
    `sap_lease_contract_number` STRING COMMENT 'The SAP S/4HANA FI lease accounting contract reference number (RE-FX or IFRS 16 module) associated with this agreement. Enables reconciliation between the operational rental_lease record and the financial accounting right-of-use asset and lease liability entries.',
    `security_deposit_amount` DECIMAL(18,2) COMMENT 'Refundable security deposit paid or received at agreement commencement. Recorded as a financial asset (inbound) or liability (outbound) in SAP FI. Null if no deposit is required.',
    `start_date` DATE COMMENT 'The date on which the rental, lease, or custom hire agreement becomes effective and the enterprise gains right-of-use or service access. Used for IFRS 16 commencement date determination and CAPEX/OPEX period allocation.',
    `total_acreage_covered` DECIMAL(18,2) COMMENT 'Total number of acres covered or serviced under this agreement. For custom hire, this is the contracted field area to be planted, sprayed, or harvested. Used for per-acre billing reconciliation and yield-per-acre (YPM) cost analysis.',
    `total_agreement_value` DECIMAL(18,2) COMMENT 'The total contracted monetary value of the agreement over its full term. For IFRS 16 finance leases, this is the undiscounted sum of lease payments. Used for CAPEX/OPEX planning, budget allocation, and lease liability recognition.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when this rental_lease record was last modified. Used for change tracking, audit trail, and incremental data pipeline processing in the Databricks Silver Layer.',
    CONSTRAINT pk_rental_lease PRIMARY KEY(`rental_lease_id`)
) COMMENT 'Records of external equipment agreements including rentals, leases, and contract farming services (custom hire) for agricultural machinery. Covers equipment obtained from external providers, leased out to third parties, and contract services where external operators perform field operations or the enterprise provides equipment/operators to others. Captures agreement type (operating lease/finance lease/rental/custom hire inbound/custom hire outbound), agreement number, counterparty identity, asset or equipment description, service type for custom hire (planting, spraying, harvesting, hauling), lease terms (start/end dates, payment schedule, mileage/hours cap, return conditions, early termination), rate structure (per acre, per hour, monthly, seasonal), total agreement value, field/acreage covered, quality/performance metrics, insurance requirements, invoice reference, and SAP FI lease accounting reference (IFRS 16). Supports fleet cost optimization decisions between owned, leased, rented, and custom-hired equipment, revenue recognition for outbound contract services, and CAPEX/OPEX planning.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`warranty_claim` (
    `warranty_claim_id` BIGINT COMMENT 'Unique system-generated identifier for each warranty claim record. Primary key for the warranty_claim data product within the equipment domain.',
    `asset_id` BIGINT COMMENT 'Reference to the agricultural equipment asset (tractor, combine, planter, sprayer, irrigation system, etc.) against which the warranty claim is filed. Links to the equipment asset master.',
    `fault_id` BIGINT COMMENT 'Foreign key linking to equipment.equipment_fault. Business justification: Warranty claims in agricultural equipment are almost always filed as a direct consequence of a specific equipment fault or DTC event. warranty_claim currently stores fault_code as a STRING but has no ',
    `gl_account_id` BIGINT COMMENT 'Foreign key linking to finance.gl_account. Business justification: Warranty claim reimbursements are posted as warranty recovery income to specific GL accounts; denied claims post to repair expense. Agriculture fleet managers track warranty recoveries as a distinct f',
    `parts_inventory_id` BIGINT COMMENT 'Foreign key linking to equipment.parts_inventory. Business justification: warranty_claim stores part_number as a STRING but has no FK to the parts_inventory master. Warranty claims are filed for specific defective parts that are tracked in the parts inventory (OEM part numb',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Equipment warranty claims for hail, flood, or storm damage require certified documentation of the precipitation event for insurance adjuster verification. Agriculture equipment insurers require linkin',
    `vendor_id` BIGINT COMMENT 'Foreign key linking to procurement.vendor. Business justification: Warranty claims are filed against the equipment dealer/OEM vendor. Linking warranty_claim to procurement.vendor enables vendor warranty performance KPI tracking (claim approval rates, reimbursement ti',
    `work_order_id` BIGINT COMMENT 'Reference to the corrective maintenance work order that documented the failure and repair activity associated with this warranty claim. Links to the equipment work_order product.',
    `approval_date` DATE COMMENT 'The calendar date on which the OEM or dealer formally approved the warranty claim. Used to measure claim adjudication cycle time and track approved claims for reimbursement follow-up.',
    `approved_repair_cost` DECIMAL(18,2) COMMENT 'The repair cost amount formally approved by the OEM or dealer for reimbursement. May differ from claimed_repair_cost due to partial approvals or rate adjustments. Used for warranty cost recovery reporting.',
    `claim_number` STRING COMMENT 'Externally-known, human-readable unique identifier for the warranty claim as assigned by the internal claims management system. Used for communication with dealers, OEMs, and internal stakeholders.. Valid values are `^WC-[0-9]{4}-[0-9]{6}$`',
    `claim_status` STRING COMMENT 'Current lifecycle status of the warranty claim through the OEM/dealer adjudication process. Tracks progression from initial submission through final payment or rejection. [ENUM-REF-CANDIDATE: submitted|under_review|approved|rejected|paid|closed — promote to reference product if additional statuses are required]. Valid values are `submitted|under_review|approved|rejected|paid|closed`',
    `claim_type` STRING COMMENT 'Classification of the warranty claim by the nature of the defect or failure being claimed. Drives OEM adjudication routing and informs procurement reliability analysis. [ENUM-REF-CANDIDATE: parts_defect|manufacturing_defect|premature_failure|design_defect|software_defect — promote to reference product if additional types are required]. Valid values are `parts_defect|manufacturing_defect|premature_failure|design_defect|software_defect`',
    `claimed_repair_cost` DECIMAL(18,2) COMMENT 'The total repair cost amount submitted to the OEM or dealer as part of the warranty claim, including labor, parts, and any external service costs. Represents the gross amount claimed before OEM adjudication.',
    `component_code` STRING COMMENT 'OEM-defined code identifying the specific component, assembly, or sub-system that is the subject of the warranty claim (e.g., engine, transmission, hydraulic pump, GPS/RTK receiver, VRA controller).',
    `component_description` STRING COMMENT 'Human-readable description of the component, part, or assembly being claimed under warranty. Complements the component_code for reporting and communication with dealers and OEMs.',
    `cost_center_code` STRING COMMENT 'SAP cost center code to which the warranty claim costs and recoveries are allocated for financial reporting and CAPEX/OPEX management. Supports cost center-level warranty cost recovery analysis.',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the warranty claim record was first created in the system. Supports audit trail requirements and data lineage tracking in the Databricks Silver Layer.',
    `currency_code` STRING COMMENT 'ISO 4217 three-letter currency code applicable to all monetary amounts on this warranty claim (claimed_repair_cost, approved_repair_cost, reimbursement_amount). Supports multi-currency operations for international equipment procurement.. Valid values are `^[A-Z]{3}$`',
    `dispute_flag` BOOLEAN COMMENT 'Indicates whether the warranty claim has been formally disputed with the OEM or dealer following an initial rejection or partial approval. True when a dispute has been raised; False otherwise.',
    `dispute_notes` STRING COMMENT 'Free-text notes documenting the basis for disputing a rejected or partially approved warranty claim, including supporting evidence references and escalation actions taken with the OEM or dealer.',
    `downtime_hours` DECIMAL(18,2) COMMENT 'Total number of hours the equipment asset was out of service due to the failure covered by this warranty claim. Used for Overall Equipment Effectiveness (OEE) impact analysis and operational loss quantification.',
    `failure_date` DATE COMMENT 'The calendar date on which the equipment failure or defect was first observed or reported in the field. Used to determine warranty coverage eligibility relative to purchase date and warranty period.',
    `failure_description` STRING COMMENT 'Detailed narrative description of the equipment failure, defect symptoms, and observed conditions at the time of failure. Supports OEM adjudication and root cause analysis.',
    `failure_hours` DECIMAL(18,2) COMMENT 'Total engine/operational hours recorded on the asset at the time of failure. Critical for warranty eligibility determination based on hour-based warranty thresholds and for OEM reliability analysis.',
    `labor_cost_claimed` DECIMAL(18,2) COMMENT 'The labor cost component of the total claimed repair cost submitted to the OEM or dealer. Enables granular cost breakdown analysis for warranty cost recovery and labor rate benchmarking.',
    `oem_case_reference` STRING COMMENT 'The case or claim reference number assigned by the Original Equipment Manufacturer (OEM) or authorized dealer upon receipt of the warranty claim submission. Used for tracking claim status with the OEM.',
    `parts_cost_claimed` DECIMAL(18,2) COMMENT 'The parts and materials cost component of the total claimed repair cost submitted to the OEM or dealer. Supports parts cost recovery tracking and procurement reliability analysis by component.',
    `payment_date` DATE COMMENT 'The calendar date on which the OEM or dealer issued the reimbursement payment for the approved warranty claim. Used for accounts receivable reconciliation and warranty cost recovery tracking.',
    `reimbursement_amount` DECIMAL(18,2) COMMENT 'The actual monetary amount received from the OEM or dealer as reimbursement for the approved warranty claim. Populated upon payment confirmation. Used for CAPEX/OPEX cost recovery reconciliation.',
    `rejection_date` DATE COMMENT 'The calendar date on which the OEM or dealer formally rejected the warranty claim. Populated only when claim_status is rejected. Used for dispute tracking and procurement reliability analysis.',
    `rejection_reason` STRING COMMENT 'Reason code provided by the OEM or dealer for rejecting the warranty claim. Informs dispute resolution and procurement decisions on equipment reliability. [ENUM-REF-CANDIDATE: out_of_warranty|operator_misuse|improper_maintenance|cosmetic_damage|no_defect_found|documentation_incomplete|other — promote to reference product if additional reasons are required]',
    `repair_completed_date` DATE COMMENT 'The calendar date on which the warranty repair was completed and the asset was returned to service. Used to calculate total repair cycle time and asset availability metrics.',
    `serial_number_component` STRING COMMENT 'Serial number of the specific failed component or part, where available. Supports traceability for batch/lot defect analysis and OEM recall investigations.',
    `submission_date` DATE COMMENT 'The calendar date on which the warranty claim was formally submitted to the dealer or OEM manufacturer. Used to calculate claim processing lead times and warranty filing compliance.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the warranty claim record was most recently modified. Supports change tracking, audit trail requirements, and incremental data pipeline processing in the Databricks Silver Layer.',
    `warranty_expiry_date` DATE COMMENT 'The date on which the applicable warranty coverage for the asset or component expires. Used to validate warranty eligibility at the time of claim submission and for proactive warranty utilization planning.',
    `warranty_type` STRING COMMENT 'Classification of the warranty coverage type under which the claim is filed. Determines applicable coverage terms, reimbursement rates, and OEM adjudication rules. [ENUM-REF-CANDIDATE: standard|extended|powertrain|precision_ag_hardware|emissions — promote to reference product if additional types are required]. Valid values are `standard|extended|powertrain|precision_ag_hardware|emissions`',
    CONSTRAINT pk_warranty_claim PRIMARY KEY(`warranty_claim_id`)
) COMMENT 'Records of warranty claims submitted to equipment manufacturers or dealers for defective parts, premature failures, or manufacturing defects. Captures claim number, asset reference, part/component claimed, failure description, failure date, hours at failure, dealer/manufacturer claim submission date, claim status (submitted/approved/rejected/paid), approved repair cost, reimbursement amount received, and OEM case reference. Supports warranty cost recovery tracking and informs procurement decisions on equipment reliability.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`custom_hire_contract` (
    `custom_hire_contract_id` BIGINT COMMENT 'Primary key for the custom_hire_contract association',
    `account_id` BIGINT COMMENT 'Foreign key linking to the customer account contracting the equipment for custom hire service',
    `asset_id` BIGINT COMMENT 'Foreign key linking to the agricultural equipment asset being contracted for custom hire service',
    `contracted_acres` DECIMAL(18,2) COMMENT 'Total number of acres of farmland agreed upon in this custom hire contract for the asset to service for the customer account. This value is specific to the asset-customer engagement and cannot reside on either master record.',
    `performance_status` STRING COMMENT 'Current operational and contractual performance status of this custom hire engagement. Tracks whether the service contract is being fulfilled, has been completed, or has encountered issues. Belongs to the contract lifecycle, not the asset or account.',
    `rate_per_hour` DECIMAL(18,2) COMMENT 'Agreed billing rate per engine/operating hour for this specific asset-account custom hire engagement. Rate varies by asset type, customer tier, and season — it belongs to the contract, not the asset or account master.',
    `service_end_date` DATE COMMENT 'Date on which the contracted equipment service engagement concludes for this specific asset-account pairing. Belongs to the contract, not the asset or account, as the same asset ends on different dates for different customers.',
    `service_start_date` DATE COMMENT 'Date on which the contracted equipment service engagement begins for this specific asset-account pairing. Belongs to the contract, not the asset or account, as the same asset starts on different dates for different customers.',
    `service_type` STRING COMMENT 'Classification of the agricultural service being performed under this custom hire contract. Defines what operation the contracted asset is performing for the customer account (e.g., HARVESTING for a combine, SPRAYING for a sprayer).',
    CONSTRAINT pk_custom_hire_contract PRIMARY KEY(`custom_hire_contract_id`)
) COMMENT 'This association product represents the Contract between an agricultural equipment asset and a customer account in custom hire operations. It captures the formal service engagement whereby a specific piece of equipment is contracted to a specific customer account for a defined period and scope of work. Each record links one asset to one account and carries the contractual terms (acreage, rate, service type) and operational performance data that exist only in the context of this specific asset-customer engagement.. Existence Justification: In agricultural custom hire operations, a single piece of equipment (e.g., a combine harvester) is contracted out to multiple customer accounts across a season, and a single customer account may contract multiple assets (combine, grain cart, tractor, sprayer) for their farming operations. The business actively manages these service contracts with specific terms including contracted acreage, hourly rates, service type, and performance tracking — this is a recognized operational concept called a Custom Hire Contract or Equipment Service Agreement that humans create, update, and close throughout the crop season.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`parts_issue` (
    `parts_issue_id` BIGINT COMMENT 'Primary key for the parts_issue association',
    `parts_inventory_id` BIGINT COMMENT 'Foreign key linking this parts issue line to the specific spare part or consumable record in the MRO inventory master.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking this parts issue line to the parent maintenance work order that consumed the part.',
    `issue_date` DATE COMMENT 'Calendar date on which the part was physically drawn from the warehouse and issued to the work order. Belongs to the issue event, not to the work order header (which has planned/actual start dates) or the inventory master.',
    `line_number` BIGINT COMMENT 'Sequential line number of this parts issue record within the work order, matching the SAP PM component line or Maximo material usage line number. Enables ordering and referencing of individual parts lines on a work order.',
    `parts_cost` DECIMAL(18,2) COMMENT 'Total monetary cost of spare parts and materials consumed against the work order, aggregated from embedded parts consumption line items. Supports OPEX cost tracking and inventory replenishment analysis. Maps to SAP MM goods issue cost (DMBTR) settled to the work order. [Moved from work_order: The work_order.parts_cost is a derived aggregate (sum of all parts issue line costs) and should be computed from parts_issue records rather than stored redundantly on the work order header. If retained on work_order for performance, it should be treated as a calculated/denormalized field, not a source-of-truth attribute. The authoritative per-part cost data lives in the parts_issue association.]',
    `quantity_issued` DECIMAL(18,2) COMMENT 'Actual quantity of the part issued from inventory to the work order, expressed in the parts base unit of measure. Belongs to the issue event, not to the work order header or the inventory master.',
    `reservation_status` STRING COMMENT 'Current lifecycle status of this material reservation/issue line: planned (on work order plan, not yet reserved), reserved (stock reserved but not yet drawn), issued (physically drawn from warehouse), partially_issued (partial quantity drawn), returned (unused quantity returned to stock), cancelled (line removed from work order). Drives inventory availability calculations and OPEX accruals.',
    `return_quantity` DECIMAL(18,2) COMMENT 'Quantity of the part returned to inventory after work order completion (unused material). Drives inventory replenishment recalculation and OPEX cost adjustment.',
    `unit_cost_at_issue` DECIMAL(18,2) COMMENT 'Unit cost of the part at the time of issue, captured from the inventory valuation at issue date. Differs from the current unit_cost on parts_inventory due to price fluctuations; belongs to this issue event for accurate historical OPEX costing.',
    CONSTRAINT pk_parts_issue PRIMARY KEY(`parts_issue_id`)
) COMMENT 'This association product represents the Parts Issue (Material Reservation) event between work_order and parts_inventory. It captures each line-item-level consumption of a spare part or consumable against a specific maintenance work order, as recorded in the CMMS (SAP PM goods issue / IBM Maximo material usage). Each record links one work_order to one parts_inventory item and carries the quantity issued, unit cost at time of issue, issue date, reservation status, and return quantity — data that exists only in the context of this specific work-order-to-part consumption event. Serves as the SSOT for actual material consumption supporting OPEX cost tracking, inventory replenishment triggers, and maintenance cost analysis by asset and crop enterprise.. Existence Justification: In agricultural CMMS operations, a single work order consumes multiple spare parts from inventory (e.g., a combine harvester repair may require an air filter, hydraulic seal, and drive belt simultaneously), and each part number is consumed across many different work orders over time. This is a textbook operational M:N: the parts issue or material reservation is a well-established CMMS business concept actively created, updated, and closed by maintenance planners and technicians. The relationship carries its own data — quantity issued, unit cost at time of issue, issue date, reservation status, and return quantity — none of which belong solely to the work order header or the parts inventory master.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`maintenance_plan_bom` (
    `maintenance_plan_bom_id` BIGINT COMMENT 'Primary key for the maintenance_plan_bom association',
    `maintenance_plan_id` BIGINT COMMENT 'Foreign key linking to the preventive maintenance plan that requires this part.',
    `parts_inventory_id` BIGINT COMMENT 'Foreign key linking to the spare part or consumable required by this maintenance plan.',
    `consumption_uom` STRING COMMENT 'The unit of measure in which the part is consumed for this specific maintenance plan cycle. May differ from the stocking UOM in parts_inventory (e.g., stocked in liters but consumed in quarts for a specific OEM procedure).',
    `estimated_cost` DECIMAL(18,2) COMMENT 'Estimated cost of the required quantity of this part for one cycle of the maintenance plan, expressed in the plans currency. Calculated as required_quantity × unit_cost at plan authoring time. Contributes to the maintenance_plan.estimated_parts_cost rollup but is tracked at line-item level here.',
    `estimated_parts_cost` DECIMAL(18,2) COMMENT 'Estimated total cost of parts and materials required to complete one cycle of this maintenance plan, in the base currency. Used for OPEX budgeting and procurement planning in SAP MM. [Moved from maintenance_plan: This is a rolled-up aggregate of all part line costs in the BOM. The authoritative line-item costs now live in the association (estimated_cost per plan-part combination). The rollup can be derived by summing association records, making the denormalized field on maintenance_plan redundant. If retained on maintenance_plan, it should be treated as a computed/cached field, not a source of truth.]',
    `is_mandatory` BOOLEAN COMMENT 'Indicates whether this part is mandatory for plan execution (true) or optional/conditional based on inspection findings (false). A mandatory part must be staged before the work order can be released; an optional part is staged on-demand.',
    `line_number` STRING COMMENT 'Sequential line number of this part within the maintenance plan BOM, used for display ordering and reference in work order printouts and CMMS integrations. Assigned by the maintenance planner at BOM authoring time.',
    `part_role` STRING COMMENT 'The functional role of this part within the maintenance plan. Describes how the part is used in the context of this specific plan (e.g., primary_consumable, replacement_component, lubricant, filter, sealant, fastener). Belongs to the association, not to the part master.',
    `required_quantity` DECIMAL(18,2) COMMENT 'The quantity of this part required to complete one full cycle of the maintenance plan. Belongs to the plan-part combination, not to the plan or part alone — the same part may be required in different quantities across different plans.',
    `substitution_allowed` BOOLEAN COMMENT 'Indicates whether an approved substitute part may be used in place of this specified part if the primary part is out of stock. When true, the work order execution team may source an approved alternate without plan deviation.',
    CONSTRAINT pk_maintenance_plan_bom PRIMARY KEY(`maintenance_plan_bom_id`)
) COMMENT 'This association product represents the Bill of Materials (BOM) contract between a preventive maintenance plan and a parts inventory item. It captures the planned parts list for each PM plan cycle, specifying which parts are required, in what quantity, in what role, and at what estimated cost. Each record links one maintenance_plan to one parts_inventory item with attributes that exist only in the context of this plan-part combination. Actively managed by maintenance planners in CMMS systems to ensure parts availability before work order execution and to drive automated procurement replenishment ahead of planting and harvest seasons.. Existence Justification: In agricultural equipment maintenance management, a preventive maintenance (PM) plan defines a Bill of Materials (BOM) specifying exactly which parts and consumables are required for each service interval — one plan requires many parts, and one part (e.g., an oil filter or hydraulic fluid) appears across many plans. This is a well-recognized operational concept in CMMS systems called a PM BOM or maintenance plan parts list, actively created and managed by maintenance planners. The relationship carries its own data (required quantity, part role, mandatory flag, estimated cost, consumption UOM) that belongs to neither the plan nor the part inventory record alone.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset_contract_allocation` (
    `asset_contract_allocation_id` BIGINT COMMENT 'Primary key for the asset_contract_allocation association',
    `asset_id` BIGINT COMMENT 'Foreign key linking this allocation record to the specific agricultural equipment asset being allocated to the contract.',
    `contract_id` BIGINT COMMENT 'Foreign key linking this allocation record to the specific sales contract against which the asset is being deployed.',
    `allocated_acreage` DECIMAL(18,2) COMMENT 'Total acreage harvested, planted, or applied by this asset in service of this specific sales contract. Used for per-contract cost allocation and field-level traceability required by GlobalGAP audits.',
    `allocated_hours` DECIMAL(18,2) COMMENT 'Total engine or operating hours attributed to this asset for fulfillment of this specific sales contract. Used for cost allocation (OPEX per contract) and asset utilization reporting. Cannot reside on the asset (which accumulates hours across all contracts) or the contract (which uses many assets).',
    `allocation_end_date` DATE COMMENT 'The date on which this assets allocation to this sales contract was completed or terminated. Used to calculate total allocation duration and close out cost allocation entries.',
    `allocation_start_date` DATE COMMENT 'The date on which this asset was formally allocated to begin servicing this sales contract. Establishes the temporal boundary of the allocation for cost and compliance reporting.',
    `allocation_status` STRING COMMENT 'Current lifecycle status of this asset-contract allocation record. Drives workflow and reporting in farm operations management systems.',
    `compliance_status` STRING COMMENT 'GlobalGAP and/or FSMA compliance certification status for this specific asset-contract pairing. Indicates whether the asset meets the compliance requirements stipulated in the sales contract (e.g., GLOBALG.A.P. certification, FSMA Produce Safety Rule). Required for audit trail and contract fulfillment verification.',
    `utilization_cost` DECIMAL(18,2) COMMENT 'Monetary cost (in contract currency or functional currency) allocated to this sales contract for the use of this asset. Derived from internal cost rates applied to allocated hours and acreage. Used for CAPEX/OPEX cost allocation per contract in SAP CO module.',
    CONSTRAINT pk_asset_contract_allocation PRIMARY KEY(`asset_contract_allocation_id`)
) COMMENT 'This association product represents the operational Allocation of a specific agricultural equipment asset to a specific sales contract. It captures the business record of which assets are deployed to fulfill which contract obligations across the crop marketing season, including hours consumed, acreage covered, compliance certification status for GlobalGAP/FSMA audit purposes, and the utilization cost allocated to the contract for financial reporting. Each record links one asset to one sales contract and carries attributes that exist only in the context of that specific asset-contract pairing — they cannot reside on the asset (which serves many contracts) or the contract (which uses many assets).. Existence Justification: In large-scale grain operations, agricultural equipment assets (harvesters, grain carts, transport vehicles) are actively allocated to specific sales contracts to fulfill delivery obligations — a single harvester services multiple contracts across a season, and a single contract may require multiple pieces of equipment simultaneously. The business operationally tracks this allocation for cost allocation (CAPEX/OPEX per contract), GlobalGAP audit compliance, and utilization reporting. This is not an analytical correlation derivable from transactional joins — it is an actively managed operational record with its own attributes (allocated hours, acreage, compliance status, utilization cost) that belong to neither the asset nor the contract alone.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`input_compatibility` (
    `input_compatibility_id` BIGINT COMMENT 'Primary key for the equipment_input_compatibility association',
    `asset_id` BIGINT COMMENT 'Foreign key linking to the agricultural equipment asset that is certified or rated for compatibility with the input product.',
    `input_product_id` BIGINT COMMENT 'Foreign key linking to the agricultural input product for which the equipment asset has been assessed for compatibility.',
    `application_rate_capability` STRING COMMENT 'The achievable application rate range (expressed as a min-max string with unit, e.g., 1.5-3.0 L/ha) for this asset when applying the linked input product. May differ from the label-specified range on input_product due to equipment-specific flow rate and nozzle constraints. Sourced directly from detection phase relationship data.',
    `certification_required` BOOLEAN COMMENT 'Indicates whether a formal equipment certification or operator licence is required before this asset may be used to apply the linked input product (e.g., for Restricted Use Pesticides or specialised application equipment). Sourced directly from detection phase relationship data.',
    `compatibility_status` STRING COMMENT 'Current status of the compatibility certification between this asset and input product. APPROVED = fully certified; CONDITIONAL = approved with documented restrictions; RESTRICTED = requires additional controls; REVOKED = previously approved but no longer valid. Supports operational filtering when planning spray applications.',
    `compatible_formulation_types` STRING COMMENT 'The specific formulation type codes (per industry-standard classification) that this asset is rated to handle for the linked input product, based on tank material compatibility, nozzle suitability, and equipment design. Sourced directly from detection phase relationship data.',
    `effective_date` DATE COMMENT 'The date on which this equipment-input compatibility record was certified, approved, or last reviewed and confirmed as valid. Used to determine whether the compatibility is current and to support audit trails for regulatory compliance. Sourced directly from detection phase relationship data.',
    CONSTRAINT pk_input_compatibility PRIMARY KEY(`input_compatibility_id`)
) COMMENT 'This association product represents the formal compatibility certification between an agricultural equipment asset and an agricultural input product. It captures which input products a given asset is approved or certified to apply, and under what conditions (rate capability, formulation type, certification status, effective date). Each record links one asset to one input_product with attributes that exist only in the context of this compatibility relationship — such as the approved application rate range achievable by that specific asset for that specific input, and whether a formal certification is required and on file.. Existence Justification: In agricultural operations, specific equipment assets (sprayers, spreaders, planters) are certified or rated for compatibility with specific input products based on material compatibility, nozzle specifications, EPA label requirements, and equipment capabilities. A single sprayer asset can be approved for many herbicide/fungicide formulations, and a single input product can be applied by many different equipment assets across a farm fleet. This compatibility relationship is actively managed by agronomists and equipment managers as a formal certification or approval record — it is not derivable from transactional application data alone.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`asset_certification_scope` (
    `asset_certification_scope_id` BIGINT COMMENT 'Primary key for the asset_certification_scope association',
    `asset_id` BIGINT COMMENT 'Foreign key linking to the agricultural asset (equipment) included within the certification scope.',
    `sustainability_certification_id` BIGINT COMMENT 'Foreign key linking to the sustainability certification under whose scope this asset is registered.',
    `applicable_standard_version` STRING COMMENT 'The specific version or revision of the certification standard under which this asset was assessed and included in scope. May differ from the certifications current scheme_standard_version if the asset was onboarded under a prior audit cycle and has not yet been re-assessed under the latest version. Sourced directly from detection-phase relationship data.',
    `compliance_verified_date` DATE COMMENT 'Date on which the assets compliance with the applicable certification standard was last formally verified for this specific certification. Belongs to the asset-certification pairing, not to either entity alone — the same asset may have different verification dates under different certifications. Sourced directly from detection-phase relationship data.',
    `exclusion_reason` STRING COMMENT 'Reason the asset was removed from or excluded from the certification scope (e.g., decommissioned, sold, failed audit, out of operational area). Null if asset remains in scope.',
    `scope_exclusion_date` DATE COMMENT 'Date on which the asset was formally removed from the certifications equipment register, if applicable. Null if the asset remains in scope. Enables historical tracking of which assets were in scope during any given certification period.',
    `scope_inclusion_date` DATE COMMENT 'Date on which the asset was formally added to the certifications equipment register and became part of the certified scope. Represents the start of this asset-certification relationship. Sourced from detection-phase attribute certification_scope_for_asset context.',
    `scope_status` STRING COMMENT 'Per-asset status within the certification scope. Indicates whether the asset is currently active within the certifications equipment register, temporarily suspended (e.g., under repair during audit window), excluded from scope, or pending initial verification. Sourced from detection-phase attribute asset_certification_status.',
    CONSTRAINT pk_asset_certification_scope PRIMARY KEY(`asset_certification_scope_id`)
) COMMENT 'This association product represents the formal inclusion of a specific agricultural asset within the scope of a sustainability certification. It captures which assets are registered under each certification, the per-asset compliance verification status, and the audit evidence linking individual equipment to certification requirements. Each record links one asset to one sustainability_certification with attributes that exist only in the context of this asset-certification pairing — such as the date compliance was verified for that asset, the assets individual status within the certification, and the standard version under which the asset was assessed.. Existence Justification: In certified agricultural supply chains, a single farm asset (e.g., a sprayer or tractor) can be in-scope for multiple sustainability certifications simultaneously (e.g., ISCC for biofuel traceability, GlobalG.A.P. for food safety, and USDA Organic for crop inputs), and a single certification covers a portfolio of assets across the farm operation. The business actively manages which specific assets are within each certifications scope, tracks per-asset compliance verification dates and statuses, and must demonstrate this linkage to auditors and buyers. This is a named, operationally managed concept in certified supply chain practice.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`inspection_checklist_template` (
    `inspection_checklist_template_id` BIGINT COMMENT 'Primary key for inspection_checklist_template',
    `parent_inspection_checklist_template_id` BIGINT COMMENT 'Self-referencing FK on inspection_checklist_template (parent_inspection_checklist_template_id)',
    `approval_status` STRING COMMENT 'Current approval status of the inspection checklist template within the quality management system, tracking review and authorization workflow.',
    `approved_by` STRING COMMENT 'Name or identifier of the person or role who approved this inspection checklist template for operational use.',
    `approved_date` DATE COMMENT 'Date when this inspection checklist template was formally approved for use in maintenance and inspection operations.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this inspection checklist template record was first created in the system.',
    `critical_items_count` STRING COMMENT 'Number of critical or mandatory inspection items that must pass for the equipment to be deemed operational or compliant.',
    `document_reference` STRING COMMENT 'Reference to external documentation, manuals, or standard operating procedures (SOPs) that provide additional context or instructions for this inspection template.',
    `effective_from_date` DATE COMMENT 'Date when this inspection checklist template version becomes effective and available for use in inspection activities.',
    `effective_until_date` DATE COMMENT 'Date when this inspection checklist template version expires or is superseded by a newer version. Nullable for templates with indefinite validity.',
    `equipment_category` STRING COMMENT 'Category of agricultural equipment this inspection template applies to, used to classify and organize templates by asset type.',
    `estimated_duration_minutes` STRING COMMENT 'Estimated time in minutes required to complete an inspection using this template, used for resource planning and scheduling.',
    `inspection_frequency_days` STRING COMMENT 'Recommended frequency in days for conducting inspections using this template, supporting preventive maintenance scheduling and compliance requirements.',
    `inspection_type` STRING COMMENT 'Type of inspection this template supports, distinguishing between preventive maintenance, corrective maintenance, safety checks, regulatory compliance, and operational readiness inspections.',
    `language_code` STRING COMMENT 'Two-letter ISO 639-1 language code indicating the language in which the inspection checklist template is written, supporting multilingual operations.',
    `last_modified_by` STRING COMMENT 'Name or identifier of the person or role who most recently modified this inspection checklist template.',
    `last_modified_timestamp` TIMESTAMP COMMENT 'Date and time when this inspection checklist template record was most recently updated or modified.',
    `manufacturer_recommended_flag` BOOLEAN COMMENT 'Indicates whether this inspection template is based on or aligned with original equipment manufacturer (OEM) recommended maintenance procedures.',
    `precision_agriculture_flag` BOOLEAN COMMENT 'Indicates whether this inspection template includes checks for precision agriculture hardware such as GPS/RTK receivers, variable rate application (VRA) controllers, or telematics systems.',
    `regulatory_compliance_flag` BOOLEAN COMMENT 'Indicates whether this inspection template is designed to meet specific regulatory or legal compliance requirements for agricultural equipment operation.',
    `requires_certification_flag` BOOLEAN COMMENT 'Indicates whether completion of this inspection requires a certified inspector or technician, supporting compliance with regulatory and safety requirements.',
    `revision_notes` STRING COMMENT 'Notes documenting changes made in the current version of the inspection checklist template, supporting change management and audit trail requirements.',
    `safety_critical_flag` BOOLEAN COMMENT 'Indicates whether this inspection template addresses safety-critical systems or components that could pose risk to operators or farm personnel if not properly maintained.',
    `seasonal_applicability` STRING COMMENT 'Indicates the seasonal context or agricultural cycle phase when this inspection template is most relevant, supporting seasonal maintenance planning.',
    `inspection_checklist_template_status` STRING COMMENT 'Current lifecycle status of the inspection checklist template, indicating whether it is available for use in inspection workflows.',
    `tags` STRING COMMENT 'Comma-separated list of keywords or tags used for categorization, search, and filtering of inspection checklist templates within the maintenance management system.',
    `template_code` STRING COMMENT 'Externally-known unique business identifier code for the inspection checklist template, used for reference in maintenance management systems and operational documentation.',
    `template_description` STRING COMMENT 'Detailed description of the inspection checklist template, including its purpose, scope, and any special instructions for inspectors.',
    `template_name` STRING COMMENT 'Human-readable name of the inspection checklist template, describing the type of inspection or equipment category it applies to.',
    `total_checklist_items` STRING COMMENT 'Total number of inspection items or checkpoints included in this template, providing a measure of inspection comprehensiveness.',
    `version_number` STRING COMMENT 'Version number of the inspection checklist template, used to track revisions and ensure inspectors are using the current approved version.',
    `created_by` STRING COMMENT 'Name or identifier of the person or role who originally created this inspection checklist template.',
    CONSTRAINT pk_inspection_checklist_template PRIMARY KEY(`inspection_checklist_template_id`)
) COMMENT 'Master reference table for inspection_checklist_template. Referenced by checklist_template_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`equipment`.`work_center` (
    `work_center_id` BIGINT COMMENT 'Primary key for work_center',
    `employee_id` BIGINT COMMENT 'Reference to the employee responsible for managing and overseeing work center operations.',
    `facility_id` BIGINT COMMENT 'Reference to the physical location or facility where this work center operates.',
    `parent_work_center_id` BIGINT COMMENT 'Self-referencing FK on work_center (parent_work_center_id)',
    `address_line_1` STRING COMMENT 'Primary street address of the work center facility.',
    `address_line_2` STRING COMMENT 'Secondary address information such as building number, suite, or unit for the work center facility.',
    `capacity_hours_per_day` DECIMAL(18,2) COMMENT 'Maximum available working hours per day for this work center, used for maintenance scheduling and resource planning.',
    `certification_level` STRING COMMENT 'Highest certification level held by the work center for equipment maintenance and repair, indicating technical capability and authorization.',
    `city` STRING COMMENT 'City where the work center is located.',
    `corrective_maintenance_flag` BOOLEAN COMMENT 'Indicates whether the work center performs corrective maintenance and breakdown repair services.',
    `cost_center_code` STRING COMMENT 'Financial cost center code for tracking capital expenditure (CAPEX) and operational expenditure (OPEX) allocation related to this work center.',
    `country_code` STRING COMMENT 'Three-letter ISO country code where the work center is located.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when the work center record was first created in the system.',
    `work_center_description` STRING COMMENT 'Detailed description of the work centers purpose, capabilities, and operational scope within the equipment maintenance and fleet management context.',
    `effective_end_date` DATE COMMENT 'Date when the work center ceased operations or was decommissioned. Null for currently active work centers.',
    `effective_start_date` DATE COMMENT 'Date when the work center became operational and available for equipment maintenance services.',
    `email_address` STRING COMMENT 'Primary email address for work center communications and service requests.',
    `equipment_specialization` STRING COMMENT 'Types of agricultural equipment this work center specializes in servicing, such as tractors, combines, planters, sprayers, or irrigation systems.',
    `facility_name` STRING COMMENT 'Name of the facility or site where the work center is located.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when the work center record was last modified or updated.',
    `work_center_name` STRING COMMENT 'Human-readable name of the work center describing its function or location within the agricultural operation.',
    `oem_authorized_flag` BOOLEAN COMMENT 'Indicates whether the work center is authorized by original equipment manufacturers such as John Deere, Case IH, or New Holland for warranty and certified repairs.',
    `operating_hours_end` STRING COMMENT 'Standard daily end time for work center operations in HH:MM format.',
    `operating_hours_start` STRING COMMENT 'Standard daily start time for work center operations in HH:MM format.',
    `parts_inventory_flag` BOOLEAN COMMENT 'Indicates whether the work center maintains an on-site parts inventory for equipment maintenance and repairs.',
    `phone_number` STRING COMMENT 'Primary contact phone number for the work center facility.',
    `postal_code` STRING COMMENT 'Postal or ZIP code for the work center facility address.',
    `precision_agriculture_support_flag` BOOLEAN COMMENT 'Indicates whether the work center provides support for precision agriculture hardware including GPS/RTK receivers and variable rate application (VRA) controllers.',
    `preventive_maintenance_flag` BOOLEAN COMMENT 'Indicates whether the work center performs scheduled preventive maintenance activities as part of its service offerings.',
    `shift_pattern` STRING COMMENT 'Standard shift pattern operated by the work center for maintenance and service activities.',
    `state_province` STRING COMMENT 'State or province where the work center is located.',
    `work_center_status` STRING COMMENT 'Current operational status of the work center indicating its availability for equipment maintenance and service activities.',
    `telematics_integration_flag` BOOLEAN COMMENT 'Indicates whether the work center has integration with telematics systems such as John Deere Operations Center for remote diagnostics and predictive maintenance.',
    `work_center_code` STRING COMMENT 'Externally-known unique alphanumeric code identifying the work center for operational reference and integration with maintenance management systems.',
    `work_center_type` STRING COMMENT 'Classification of the work center based on its primary function within the equipment domain.',
    CONSTRAINT pk_work_center PRIMARY KEY(`work_center_id`)
) COMMENT 'Master reference table for work_center. Referenced by work_center_id.';

